window.__ppEditSale = async function(saleId) {
 if(typeof db === 'undefined' || !db) return;
 try {
 const { data: row, error } = await db.from('sales_history').select('*').eq('id', saleId).single();
 if(error) throw error;
 if(!row) return;
 const set = (id, v) => { const el = document.getElementById(id); if(el) el.value = (v == null ? '' : String(v)); };
 set('ppEditId', row.id);
 const dt = new Date(row.created_at);
 const dtStr = dt.toLocaleString('en-MY', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit', hour12:true });
 const idEl = document.getElementById('ppEditSaleId'); if(idEl) idEl.textContent = row.id;
 const dateEl = document.getElementById('ppEditSaleDate'); if(dateEl) dateEl.textContent = dtStr;
 set('ppEditCustName', row.customer_name);
 set('ppEditCustPhone', row.customer_phone);
 set('ppEditCustEmail', row.customer_email);
 set('ppEditMethod', row.payment_method || 'Cash');
 set('ppEditChannel', row.channel || 'POS Cashier');
 set('ppEditTotal', row.total_amount != null ? row.total_amount : (row.total != null ? row.total : ''));
 set('ppEditStatus', row.status || 'Completed');
 set('ppEditBuyerTin', row.buyer_tin);
 set('ppEditNote', '');
 const modal = document.getElementById('ppEditModal');
 if(modal) modal.style.display = 'flex';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 } catch(e) {
 if(typeof showToast === 'function') showToast('Edit gagal load: ' + e.message, 'error');
 }
};

// p1_235 — Customer autocomplete dalam Edit Sale modal (Zaid: "masa ariff edit sales, dia tak keluar memori customer")
window.__ppEditAcResults = [];

window.__ppEditCustAutocomplete = function() {
 const inp = document.getElementById('ppEditCustName');
 const dd = document.getElementById('ppEditCustAcDropdown');
 if(!inp || !dd) return;
 const q = (inp.value || '').trim().toLowerCase();
 const list = (typeof customersData !== 'undefined' && Array.isArray(customersData)) ? customersData : [];
 if(!list.length) { dd.style.display = 'none'; return; }
 let results;
 if(!q) {
 results = [...list].sort((a,b) => (b.total_spent||0) - (a.total_spent||0)).slice(0, 8);
 } else {
 results = list.filter(c => {
 const hay = `${c.name||''} ${c.phone||''} ${c.email||''}`.toLowerCase();
 return hay.includes(q);
 }).slice(0, 8);
 }
 window.__ppEditAcResults = results;
 if(results.length === 0) {
 dd.innerHTML = '<div style="padding:10px; font-size:12px; color:#9CA3AF; text-align:center;">Tiada match — kosongkan field atau klik "Cari / Daftar Baru" untuk register</div>';
 dd.style.display = 'block';
 return;
 }
 const escHtml = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;');
 dd.innerHTML = results.map((c, i) => {
 const pts = parseInt(c.points || 0);
 const badge = c.is_member ? '<span style="background:#FEF3C7; color:#92400E; padding:1px 5px; border-radius:3px; font-size:9px; font-weight:700; margin-left:4px;">VIP</span>' : '';
 return `<div onmousedown="window.__ppEditCustPick(${i})" style="padding:8px 12px; border-bottom:1px solid #F3F4F6; cursor:pointer;" onmouseover="this.style.background='#F9FAFB'" onmouseout="this.style.background=''">
 <div style="font-size:12.5px; font-weight:700; color:#111;">${escHtml(c.name || '(no name)')}${badge}</div>
 <div style="font-size:10.5px; color:#6B7280; margin-top:2px;">${escHtml(c.phone || '-')}${c.email ? ' · ' + escHtml(c.email.slice(0,30)) : ''} · ${c.total_orders||0} orders · RM${(c.total_spent||0).toFixed(0)}</div>
 </div>`;
 }).join('');
 dd.style.display = 'block';
};

window.__ppEditCustAcClose = function() {
 const dd = document.getElementById('ppEditCustAcDropdown');
 if(dd) dd.style.display = 'none';
};

window.__ppEditCustPick = function(i) {
 const c = (window.__ppEditAcResults || [])[i];
 if(!c) return;
 const set = (id, v) => { const el = document.getElementById(id); if(el) el.value = (v == null ? '' : String(v)); };
 set('ppEditCustName', c.name);
 set('ppEditCustPhone', c.phone);
 set('ppEditCustEmail', c.email);
 window.__ppEditCustAcClose();
 if(typeof showToast === 'function') showToast(`${c.name || c.phone} loaded.`, 'success');
};

// p1_235 — Open customer picker modal dari Edit Sale modal (untuk daftar baru atau search luas)
window.__ppEditOpenPicker = function() {
 // Open the existing customer picker modal (p1_229) — but intercept cpkPick/cpkAddNewCustomer to sync to ppEdit fields ganti posCustomer
 window.__ppEditPickerActive = true;
 if(typeof window.posAttachCustomer === 'function') window.posAttachCustomer();
};

window.__ppSaveEdit = async function() {
 if(typeof db === 'undefined' || !db) return;
 const get = (id) => (document.getElementById(id)?.value || '').trim();
 const saleId = parseInt(get('ppEditId'), 10);
 if(!saleId) return;
 const totalRaw = get('ppEditTotal');
 const total = parseFloat(totalRaw);
 if(totalRaw !== '' && (isNaN(total) || total < 0)) {
 if(typeof showToast === 'function') showToast('Total amount tak valid.', 'warn'); return;
 }
 const editNote = get('ppEditNote');
 const u = window.currentUser || {};
 // Build update payload + audit entry
 const payload = {
 customer_name: get('ppEditCustName') || 'Walk-In',
 customer_phone: get('ppEditCustPhone') || null,
 customer_email: get('ppEditCustEmail') || null,
 payment_method: get('ppEditMethod') || 'Cash',
 channel: get('ppEditChannel') || 'POS Cashier',
 status: get('ppEditStatus') || 'Completed',
 buyer_tin: get('ppEditBuyerTin') || null
 };
 if(!isNaN(total)) { payload.total_amount = total; payload.total = total; }
 try {
 const { error } = await db.from('sales_history').update(payload).eq('id', saleId);
 if(error) throw error;
 // Audit log
 try {
 await db.from('audit_logs').insert([{
 action_type: 'sale_edit',
 actor_name: u.name || 'System',
 details: JSON.stringify({ sale_id: saleId, changes: payload, note: editNote || null }),
 created_at: new Date().toISOString()
 }]);
 } catch(_){}
 if(typeof showToast === 'function') showToast(`Sale #${saleId} updated.`, 'success');
 document.getElementById('ppEditModal').style.display = 'none';
 if(typeof window.renderPaymentProofs === 'function') window.renderPaymentProofs();
 } catch(e) {
 if(typeof showToast === 'function') showToast('Simpan gagal: ' + e.message, 'error');
 }
};

window.__ppUploadFor = function(saleId) {
 const input = document.createElement('input');
 input.type = 'file';
 input.accept = 'image/*,application/pdf';
 input.onchange = async () => {
 const f = input.files && input.files[0];
 if(!f) return;
 if(f.size > 5 * 1024 * 1024) { if(typeof showToast==='function') showToast('Saiz lebih 5MB', 'warn'); return; }
 if(typeof db === 'undefined' || !db) return;
 try {
 const ext = (f.name.split('.').pop() || 'jpg').toLowerCase();
 const ts = new Date().toISOString().replace(/[:.]/g, '-');
 const fileName = saleId + '_' + ts + '.' + ext;
 const { data, error } = await db.storage.from('payment-proofs').upload(fileName, f, { cacheControl: '3600', upsert: false, contentType: f.type || 'application/octet-stream' });
 if(error) throw error;
 const { data: pub } = db.storage.from('payment-proofs').getPublicUrl(data.path);
 const uploaderName = (window.currentUser && window.currentUser.name) ? window.currentUser.name : 'Unknown';
 await db.from('sales_history').update({
 payment_proof_url: pub.publicUrl,
 payment_proof_uploaded_at: new Date().toISOString(),
 payment_proof_uploaded_by: uploaderName
 }).eq('id', saleId);
 if(typeof showToast==='function') showToast('Resit dah saved untuk sale #' + saleId, 'success');
 // p1_257 — auto-trigger HEIC conversion (kalau staff upload .heic)
 if(typeof window.__triggerHeicConvertIfNeeded === 'function') {
 window.__triggerHeicConvertIfNeeded(saleId, pub.publicUrl);
 }
 window.renderPaymentProofs();
 } catch(e) {
 if(typeof showToast==='function') showToast('Upload gagal: ' + e.message, 'error');
 }
 };
 input.click();
};

window.renderFeedbackInbox = async function() {
 const wrap = document.getElementById('fbInboxList');
 const statsEl = document.getElementById('fbInboxStats');
 if(!wrap) return;
 // p1_210 — non-Bos view = read-only (transparency without authority).
 const _u = window.currentUser || (typeof currentUser !== 'undefined' ? currentUser : null);
 const _isBoss = !!(_u && typeof window.isBoss === 'function' && window.isBoss(_u));
 try {
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 const { data, error } = await db.from('staff_feedback').select('*').order('posted_at', { ascending: false }).limit(200);
 if(error) throw error;
 let rows = data || [];
 // Stats (always all rows)
 if(statsEl) {
 const all = rows;
 const counts = {
 total: all.length,
 new: all.filter(r => r.status === 'new').length,
 critical: all.filter(r => r.severity === 'critical' && r.status !== 'resolved' && r.status !== 'wontfix').length,
 in_progress: all.filter(r => r.status === 'in_progress').length,
 resolved: all.filter(r => r.status === 'resolved').length
 };
 statsEl.innerHTML = `
 <div style="background:#F3F4F6; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#6B7280;">Total</div><div style="font-size:18px; font-weight:bold;">${counts.total}</div></div>
 <div style="background:#FEF3C7; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#92400E;">Baru</div><div style="font-size:18px; font-weight:bold;">${counts.new}</div></div>
 <div style="background:${counts.critical > 0 ? '#FEE2E2' : '#F3F4F6'}; padding:10px; border-radius:6px;"><div style="font-size:10px; color:${counts.critical > 0 ? '#991B1B' : '#6B7280'};">Critical Open</div><div style="font-size:18px; font-weight:bold; color:${counts.critical > 0 ? '#DC2626' : '#111'};">${counts.critical}</div></div>
 <div style="background:#FAE8FF; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#86198F;">Dalam Progress</div><div style="font-size:18px; font-weight:bold;">${counts.in_progress}</div></div>
 <div style="background:#D1FAE5; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#065F46;">Resolved</div><div style="font-size:18px; font-weight:bold;">${counts.resolved}</div></div>
 `;
 }
 // Filter
 const filter = window.__fbiFilter;
 if(filter === 'critical') rows = rows.filter(r => r.severity === 'critical' && r.status !== 'resolved' && r.status !== 'wontfix');
 else if(filter !== 'all') rows = rows.filter(r => r.status === filter);
 if(!rows.length) { wrap.innerHTML = '<p style="color:#9CA3AF; padding:30px; text-align:center;">Tiada aduan dengan filter ni.</p>'; return; }
 const escHtml = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;');
 const escAttr = (s) => String(s == null ? '' : s).replace(/"/g,'&quot;').replace(/'/g,"&#39;");
 const ago = (iso) => {
 const ms = Date.now() - new Date(iso).getTime();
 const min = Math.floor(ms / 60000);
 if(min < 1) return 'baru tadi';
 if(min < 60) return min + ' min lepas';
 const hr = Math.floor(min / 60);
 if(hr < 24) return hr + ' jam lepas';
 return Math.floor(hr / 24) + ' hari lepas';
 };
 wrap.innerHTML = rows.map(r => {
 const cat = FB_CAT[r.category] || FB_CAT.other;
 const sev = FB_SEV[r.severity] || FB_SEV.medium;
 const st = FB_STATUS[r.status] || FB_STATUS.new;
 const initials = (r.staff_name || '').split(' ').map(p => p[0]).slice(0,2).join('').toUpperCase();
 return `<div style="padding:16px; border:1px solid var(--border-color); border-left:4px solid ${sev.color}; border-radius:10px; margin-bottom:10px; background:#fff;">
 <div style="display:flex; justify-content:space-between; gap:10px; align-items:start; margin-bottom:8px; flex-wrap:wrap;">
 <div style="display:flex; gap:10px; align-items:center;">
 <span class="rp-staff-avatar" style="width:34px; height:34px; font-size:12px;">${escHtml(initials)}</span>
 <div>
 <div style="font-weight:700; font-size:13px;">${escHtml(r.staff_name)}</div>
 <div style="font-size:11px; color:#6B7280;">${escHtml(r.staff_id || '')} · ${ago(r.posted_at)}</div>
 </div>
 </div>
 <div style="display:flex; gap:6px; flex-wrap:wrap;">
 <span style="padding:2px 8px; border-radius:50px; background:${cat.bg}; color:${cat.fg}; font-size:10px; font-weight:700;">${cat.label}</span>
 <span style="padding:2px 8px; border-radius:50px; background:${st.bg}; color:${st.fg}; font-size:10px; font-weight:700;">${st.label}</span>
 <span style="padding:2px 8px; border-radius:50px; background:${sev.color}; color:#FFF; font-size:10px; font-weight:700;">${sev.label}</span>
 </div>
 </div>
 <div style="font-weight:700; font-size:14px; color:#111; margin-bottom:6px;">${escHtml(r.title)}</div>
 <div style="font-size:12.5px; color:#374151; line-height:1.55; white-space:pre-wrap; margin-bottom:12px;">${escHtml(r.body)}</div>
 <!-- Workflow controls -->
 ${_isBoss ? `<div style="background:#F9FAFB; padding:10px; border-radius:6px;">
 <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px; margin-bottom:8px;">
 <div>
 <label style="font-size:10px; color:#6B7280; font-weight:700; text-transform:uppercase;">Status</label>
 <select id="fbi-status-${r.id}" class="rp-manual-input" style="padding:6px; font-size:12px; margin-top:2px;">
 ${Object.entries(FB_STATUS).map(([k, v]) => `<option value="${k}" ${k === r.status ? 'selected' : ''}>${v.label}</option>`).join('')}
 </select>
 </div>
 <div>
 <label style="font-size:10px; color:#6B7280; font-weight:700; text-transform:uppercase;">Tindakan Singkat</label>
 <input id="fbi-action-${r.id}" type="text" class="rp-manual-input" placeholder="Cth: Tukar setting printer" value="${escAttr(r.bos_action || '')}" maxlength="200" style="padding:6px; font-size:12px; margin-top:2px;">
 </div>
 </div>
 <label style="font-size:10px; color:#6B7280; font-weight:700; text-transform:uppercase;">Reply Bos (visible ke staff)</label>
 <textarea id="fbi-reply-${r.id}" class="rp-manual-input" rows="2" placeholder="Cth: Terima kasih, akan check thermal printer setting esok pagi" maxlength="1000" style="padding:6px; font-size:12px; margin-top:2px;">${escHtml(r.bos_reply || '')}</textarea>
 <div style="display:flex; gap:6px; margin-top:8px; justify-content:space-between; align-items:center; flex-wrap:wrap;">
 <div style="display:flex; gap:4px; flex-wrap:wrap;">
 ${r.status !== 'triaged' ? `<button class="rm-pill" onclick="window.__fbiQuickStatus(${r.id}, 'triaged')" style="font-size:11px; padding:5px 10px;" title="Tandai Triaged"><i data-lucide="eye" style="width:11px; height:11px;"></i> Triage</button>` : ''}
 ${r.status !== 'in_progress' ? `<button class="rm-pill" onclick="window.__fbiQuickStatus(${r.id}, 'in_progress')" style="font-size:11px; padding:5px 10px; background:#FAE8FF; color:#86198F; border-color:#FAE8FF;" title="Tandai Dalam Progress"><i data-lucide="loader" style="width:11px; height:11px;"></i> Process</button>` : ''}
 ${r.status !== 'resolved' ? `<button class="rm-pill" onclick="window.__fbiQuickStatus(${r.id}, 'resolved')" style="font-size:11px; padding:5px 10px; background:#D1FAE5; color:#065F46; border-color:#A7F3D0;" title="Tandai Resolved"><i data-lucide="check-circle" style="width:11px; height:11px;"></i> Tandai Resolved</button>` : ''}
 ${r.status !== 'wontfix' ? `<button class="rm-pill" onclick="window.__fbiQuickStatus(${r.id}, 'wontfix')" style="font-size:11px; padding:5px 10px;" title="Tak akan fix"><i data-lucide="x-circle" style="width:11px; height:11px;"></i> Wontfix</button>` : ''}
 </div>
 <button class="rp-manual-save" onclick="window.__fbiSave(${r.id})" style="font-size:11px; padding:6px 12px;"><i data-lucide="save" style="width:11px; height:11px;"></i> Simpan</button>
 </div>
 </div>` : (r.bos_reply || r.bos_action) ? `<div style="background:rgba(16,185,129,.06); padding:10px; border-left:3px solid #10B981; border-radius:6px;">
 <div style="font-size:10px; color:#065F46; font-weight:700; text-transform:uppercase; margin-bottom:4px;"><i data-lucide="reply" style="width:11px; height:11px; vertical-align:middle;"></i> Reply Bos</div>
 ${r.bos_reply ? `<div style="font-size:12.5px; color:#111; white-space:pre-wrap;">${escHtml(r.bos_reply)}</div>` : ''}
 ${r.bos_action ? `<div style="font-size:11px; color:#065F46; margin-top:4px;"><strong>Tindakan:</strong> ${escHtml(r.bos_action)}</div>` : ''}
 </div>` : `<div style="font-size:11px; color:#9CA3AF; padding:8px 0; font-style:italic;">Belum ada reply dari Bos.</div>`}
 </div>`;
 }).join('');
 if(window.lucide && lucide.createIcons) lucide.createIcons();
 } catch(e) {
 wrap.innerHTML = '<p style="color:#EF4444; padding:20px;">Error: ' + e.message + '</p>';
 }
};

window.__fbiSave = async function(id) {
 try {
 const status = document.getElementById('fbi-status-' + id).value;
 const action = (document.getElementById('fbi-action-' + id).value || '').trim();
 const reply = (document.getElementById('fbi-reply-' + id).value || '').trim();
 const payload = { status, bos_action: action || null, bos_reply: reply || null, updated_at: new Date().toISOString() };
 if(status === 'triaged') payload.triaged_at = new Date().toISOString();
 if(status === 'resolved' || status === 'wontfix') payload.resolved_at = new Date().toISOString();
 const { error } = await db.from('staff_feedback').update(payload).eq('id', id);
 if(error) throw error;
 if(typeof showToast === 'function') showToast('Updated.', 'success');
 window.renderFeedbackInbox();
 if(typeof window.refreshRailBadges === 'function') window.refreshRailBadges();
 } catch(e) { if(typeof showToast === 'function') showToast('Save gagal: ' + e.message, 'error'); }
};

// p1_150 — Quick-action status transitions. Preserves whatever Bos has typed in
// the Tindakan + Reply fields (kalau ada), so click "Tandai Resolved" terus save.
window.__fbiQuickStatus = async function(id, newStatus) {
 try {
 // Preserve currently typed reply + action (form values, not stale DB values)
 const actionEl = document.getElementById('fbi-action-' + id);
 const replyEl = document.getElementById('fbi-reply-' + id);
 const action = actionEl ? (actionEl.value || '').trim() : '';
 const reply = replyEl ? (replyEl.value || '').trim() : '';
 const payload = { status: newStatus, updated_at: new Date().toISOString() };
 if(action) payload.bos_action = action;
 if(reply) payload.bos_reply = reply;
 if(newStatus === 'triaged') payload.triaged_at = new Date().toISOString();
 if(newStatus === 'resolved' || newStatus === 'wontfix') payload.resolved_at = new Date().toISOString();
 const { error } = await db.from('staff_feedback').update(payload).eq('id', id);
 if(error) throw error;
 const label = ({ triaged:'Triaged', in_progress:'Dalam Progress', resolved:'Resolved', wontfix:'Wontfix' })[newStatus] || newStatus;
 if(typeof showToast === 'function') showToast('Tandai ' + label + '.', 'success');
 window.renderFeedbackInbox();
 if(typeof window.refreshRailBadges === 'function') window.refreshRailBadges();
 } catch(e) { if(typeof showToast === 'function') showToast('Update gagal: ' + e.message, 'error'); }
};

// Map data-tab → which rail it belongs to (used for auto-sync rail with current section)
window.__tabToRail = function(tab) {
 if(!tab) return null;
 if(tab === 'overview') return 'overview';
 if(tab === 'memo_board') return 'memo';
 if(tab === 'roadmap') return 'roadmap';
 if(tab.startsWith('sales_')) return 'sales';
 if(tab.startsWith('customers_')) return 'customers';
 if(tab.startsWith('inv_') || tab === 'hr_roster' || tab === 'inv_floorprice' || tab === 'inv_stockcheck' || tab === 'inv_check_history' || tab === 'inv_check_sessions' || tab === 'inv_pricehistory' || tab === 'inv_reorder' || tab === 'inv_supplier' || tab === 'inv_returns') return 'inv';
 if(tab.startsWith('hr_')) return 'hr';
 if(tab === 'admin_audit_alerts' || tab === 'admin_dashboard' || tab === 'admin_invoice' || tab === 'admin_bulk_ops') return 'admin';
 if(tab === 'admin_promotions' || tab === 'admin_wa_broadcast' || tab === 'admin_reengage' || tab === 'admin_channelprofit' || tab === 'admin_brandperf' || tab === 'admin_mktweekly') return 'marketing';
 if(tab === 'report_my' || tab === 'report_team' || tab === 'staff_feedback' || tab === 'feedback_inbox') return 'reports';
 if(tab === 'settings_hub' || tab.startsWith('finance_') || tab.startsWith('admin_settings') || tab === 'admin_payments' || tab === 'admin_sync' || tab === 'admin_test_guide' || tab === 'hq_permissions') return 'hq_setup';
 return null;
};

// p1_88: aggregate badges on rail icons (memo + roster+claim → hr; fulfillment → inv; audit → admin)
window.refreshRailBadges = function() {
 const setBadge = (id, count) => {
 const b = document.getElementById(id);
 if(!b) return;
 if(count > 0) { b.style.display = ''; b.textContent = count; }
 else b.style.display = 'none';
 };
 // Memo (Bos sees pending memo)
 try {
 if(typeof window.memoGetPendingCount === 'function' && typeof window.isBoss === 'function' && window.isBoss(window.currentUser)) {
 setBadge('railBadgeMemo', window.memoGetPendingCount());
 } else setBadge('railBadgeMemo', 0);
 } catch(e){}
 // HR: roster pending + claim pending
 try {
 const u = window.currentUser;
 const roster = (typeof pendingSchedules !== 'undefined' && Array.isArray(pendingSchedules)) ? pendingSchedules.length : 0;
 const claims = (typeof _hrcLoadClaims === 'function') ? _hrcLoadClaims().filter(c => c.status === 'pending').length : 0;
 const isApprover = u && (typeof window.isBoss === 'function' && window.isBoss(u)) || (u && u.staff_id === 'CMP008');
 setBadge('railBadgeHr', isApprover ? (roster + claims) : 0);
 } catch(e){}
 // Fulfillment (Pesanan Online)
 try {
 const orders = (typeof ffOnlineOrders === 'function') ? ffOnlineOrders() : [];
 const toFulfil = orders.filter(o => (typeof ffStage === 'function' ? ffStage(o) : 'to_fulfil') === 'to_fulfil').length;
 setBadge('railBadgeFulfill', toFulfil);
 } catch(e){}
 // Audit
 try {
 const el = document.getElementById('auditAlertBadge');
 const txt = el ? parseInt(el.textContent || '0') : 0;
 setBadge('railBadgeAudit', isNaN(txt) ? 0 : txt);
 } catch(e){}
 // p1_133 — Reports rail: unread submissions for Bos/mgmt
 try {
 const u = window.currentUser;
 const canSee = u && ((typeof window.isBoss === 'function' && window.isBoss(u)) || u.role === 'mgmt');
 if(!canSee) setBadge('railBadgeReportEscalation', 0);
 else if(typeof db !== 'undefined' && db) {
 db.from('staff_report_submissions').select('id', { count: 'exact', head: true }).is('bos_read_at', null)
 .then(({ count }) => setBadge('railBadgeReportEscalation', count || 0))
 .catch(() => {});
 }
 } catch(e){}
 // p1_146/147 — Feedback badges
 try {
 const u = window.currentUser;
 if(!u || typeof db === 'undefined' || !db) return;
 // Staff side: count own unread Bos replies (posts dengan bos_reply tapi staff belum tengok)
 // For simplicity: count own posts in 'new' status that have bos_reply (means Bos replied since)
 db.from('staff_feedback').select('id', { count: 'exact', head: true }).eq('staff_id', u.staff_id).not('bos_reply', 'is', null).in('status', ['new','triaged','in_progress'])
 .then(({ count }) => setBadge('sidebarFeedbackBadge', count || 0))
 .catch(() => {});
 // Bos side: count new feedback (status=new) + critical open
 const isMgmt = (typeof window.isBoss === 'function' && window.isBoss(u)) || u.role === 'mgmt';
 if(isMgmt) {
 db.from('staff_feedback').select('id', { count: 'exact', head: true }).in('status', ['new','triaged','in_progress'])
 .then(({ count }) => setBadge('sidebarFeedbackInboxBadge', count || 0))
 .catch(() => {});
 } else setBadge('sidebarFeedbackInboxBadge', 0);
 } catch(e){}
};

function switchHub(sectionIds, title, btnElement) {
 // p1_188 — Auto-exit Landing preview mode. previewLanding() hides posAppLayout
 // which contains all .tab-section. Without this, switching sections from
 // landing-preview keeps content invisible (parent hidden). Same fix as
 // __panicShow but for the normal switchHub flow.
 const shop = document.getElementById('shopAppLayout');
 const pos = document.getElementById('posAppLayout');
 const previewBanner = document.getElementById('previewBackBanner');
 if(pos && pos.style.display === 'none') {
 if(shop) { shop.style.display = 'none'; shop.style.paddingTop = ''; }
 pos.style.display = 'block';
 if(previewBanner) previewBanner.style.display = 'none';
 }
 // Hide all sections first
 document.querySelectorAll('.tab-section').forEach(s => s.style.display = 'none');
 
 // Show requested sections
 sectionIds.forEach(id => {
 const el = document.getElementById(id);
 if(el) el.style.display = 'block';
 });
 
 // Set Window Title (legacy + new breadcrumb)
 const oldTitle = document.getElementById('pageTitle');
 if(oldTitle) oldTitle.textContent = title;
 if(typeof updateBreadcrumb === 'function') updateBreadcrumb(title);

 // p1_40: align in-section page heading to sidebar label so they never disagree.
 // Looks for an explicit [data-page-title] marker first; otherwise the first h1/h2
 // inside the section. Preserves icon children — only replaces text nodes.
 // Opt-out via [data-skip-title-sync]. Runs immediately AND on next tick so
 // sections that re-render via innerHTML (e.g. renderShiftSection) still get aligned.
 const __syncSectionTitles = () => {
 sectionIds.forEach(id => {
 const sec = document.getElementById(id);
 if (!sec) return;
 let target = sec.querySelector('[data-page-title]');
 if (!target) target = sec.querySelector('h1, h2');
 if (!target || target.hasAttribute('data-skip-title-sync')) return;
 let replaced = false;
 Array.from(target.childNodes).forEach(node => {
 if (node.nodeType === 3 /* TEXT_NODE */ && node.textContent.trim()) {
 if (!replaced) { node.textContent = ' ' + title; replaced = true; }
 else { node.textContent = ''; }
 }
 });
 if (!replaced) target.appendChild(document.createTextNode(' ' + title));
 });
 };
 if (title) {
 __syncSectionTitles();
 setTimeout(__syncSectionTitles, 0); // backstop for render functions that fire after switchHub
 }
 
 // Update active state in sidebar
 document.querySelectorAll('.menu-item').forEach(item => item.classList.remove('active'));
 if(btnElement) btnElement.classList.add('active');
 
 // Close sidebar on mobile if open
 const sidebar = document.getElementById("appSidebar");
 if(sidebar && sidebar.classList.contains("open")) toggleSidebar();

 // Contextual renders based on the hub being opened
 if(sectionIds.includes('homeSection')) renderDashboard();
 if(sectionIds.includes('posSection')) {
 const term = document.getElementById("posSearchBox") ? document.getElementById("posSearchBox").value : "";
 renderPOS(term);
 }
 if(sectionIds.includes('stockTakeSection')) renderAuditCards();

 if(sectionIds.includes('mgmtPlaceholders')) renderMgmtPlaceholders();
 if(sectionIds.includes('rosterSection')) renderStaffSchedule();
 // p1_179 — Product Master section explicit render (was relying on DOMContentLoaded
 // click listener with 100ms setTimeout; Zaid reported white screen).
 if(sectionIds.includes('databaseSection') && typeof renderProductDatabase === 'function') renderProductDatabase();
 if(sectionIds.includes('collectionsSection') && typeof renderCollections === 'function') renderCollections();
 // p1_186 — Aduan & Cadangan defense in depth (Zaid: still blank). Force visible
 // attributes (some style cascade may keep block from rendering) + call render.
 if(sectionIds.includes('feedbackSection')) {
 const fs = document.getElementById('feedbackSection');
 if(fs) {
 fs.style.display = 'block';
 fs.style.visibility = 'visible';
 fs.style.opacity = '1';
 fs.removeAttribute('hidden');
 }
 if(typeof renderFeedbackSection === 'function') {
 try { renderFeedbackSection(); } catch(e) { console.error('[Aduan] render threw:', e); }
 }
 }
}

// p1_196 — Reusable image zoom modal. Click any thumbnail with class "zoom-hotspot"
// → opens fullscreen zoom modal with wheel/pinch/drag/+/- controls.
window.__imgZoomState = { scale: 1, tx: 0, ty: 0 };

window.__imgZoomApply = function() {
 const img = document.getElementById('imgZoomImg');
 if(!img) return;
 const s = window.__imgZoomState;
 img.style.transform = 'translate(' + s.tx + 'px,' + s.ty + 'px) scale(' + s.scale + ')';
 const scaleLbl = document.getElementById('imgZoomScale');
 if(scaleLbl) scaleLbl.textContent = Math.round(s.scale * 100) + '%';
};

window.__imgZoomAdj = function(factor) {
 const s = window.__imgZoomState;
 s.scale = Math.max(0.5, Math.min(8, s.scale * factor));
 window.__imgZoomApply();
};

window.__imgZoomReset = function() {
 window.__imgZoomState = { scale: 1, tx: 0, ty: 0 };
 window.__imgZoomApply();
};

window.__imgZoomClose = function() {
 const modal = document.getElementById('imgZoomModal');
 if(modal) modal.style.display = 'none';
};

window.__imgZoom = function(src, alt) {
 if(!src) return;
 let modal = document.getElementById('imgZoomModal');
 if(!modal) {
 modal = document.createElement('div');
 modal.id = 'imgZoomModal';
 modal.className = 'img-zoom-modal';
 modal.innerHTML = `
 <button class="img-zoom-close" aria-label="Close" onclick="window.__imgZoomClose()">×</button>
 <div class="img-zoom-controls">
 <button class="img-zoom-btn" onclick="window.__imgZoomAdj(0.8)" aria-label="Zoom out">−</button>
 <span class="img-zoom-scale" id="imgZoomScale">100%</span>
 <button class="img-zoom-btn" onclick="window.__imgZoomAdj(1.25)" aria-label="Zoom in">+</button>
 <button class="img-zoom-btn" onclick="window.__imgZoomReset()" style="min-width:auto; padding:6px 12px;">Reset</button>
 </div>
 <div class="img-zoom-stage" id="imgZoomStage">
 <img id="imgZoomImg" alt="" draggable="false">
 </div>`;
 document.body.appendChild(modal);
 // Wheel zoom
 modal.addEventListener('wheel', (e) => {
 e.preventDefault();
 window.__imgZoomAdj(e.deltaY < 0 ? 1.1 : 0.9);
 }, { passive: false });
 // Click outside image to close
 modal.addEventListener('click', (e) => {
 if(e.target === modal || e.target.id === 'imgZoomStage') window.__imgZoomClose();
 });
 // ESC to close
 document.addEventListener('keydown', (e) => {
 if(e.key === 'Escape' && modal.style.display === 'flex') window.__imgZoomClose();
 });
 // Drag pan
 const stageImg = modal.querySelector('#imgZoomImg');
 let dragging = false, sx = 0, sy = 0;
 stageImg.addEventListener('pointerdown', (e) => {
 dragging = true;
 sx = e.clientX - window.__imgZoomState.tx;
 sy = e.clientY - window.__imgZoomState.ty;
 try { stageImg.setPointerCapture(e.pointerId); } catch(_) {}
 });
 stageImg.addEventListener('pointermove', (e) => {
 if(!dragging) return;
 window.__imgZoomState.tx = e.clientX - sx;
 window.__imgZoomState.ty = e.clientY - sy;
 window.__imgZoomApply();
 });
 stageImg.addEventListener('pointerup', () => { dragging = false; });
 stageImg.addEventListener('pointercancel', () => { dragging = false; });
 // Double-click toggle 1x ↔ 2x
 stageImg.addEventListener('dblclick', () => {
 if(window.__imgZoomState.scale > 1.1) window.__imgZoomReset();
 else window.__imgZoomAdj(2);
 });
 // Pinch zoom (basic 2-pointer)
 const activePointers = new Map();
 let lastPinchDist = 0;
 stageImg.addEventListener('pointerdown', (e) => activePointers.set(e.pointerId, e));
 stageImg.addEventListener('pointermove', (e) => {
 if(activePointers.size === 2) {
 const pts = Array.from(activePointers.values());
 const dx = pts[0].clientX - pts[1].clientX;
 const dy = pts[0].clientY - pts[1].clientY;
 const dist = Math.hypot(dx, dy);
 if(lastPinchDist > 0) window.__imgZoomAdj(dist / lastPinchDist);
 lastPinchDist = dist;
 }
 });
 stageImg.addEventListener('pointerup', (e) => { activePointers.delete(e.pointerId); if(activePointers.size < 2) lastPinchDist = 0; });
 }
 window.__imgZoomState = { scale: 1, tx: 0, ty: 0 };
 const img = document.getElementById('imgZoomImg');
 img.src = src;
 img.alt = alt || '';
 modal.style.display = 'flex';
 window.__imgZoomApply();
};

