function __getDashDateRange() {
 const r = window.__dashRange || 'today';
 const now = new Date();
 const startOf = (d) => { const x = new Date(d); x.setHours(0,0,0,0); return x; };
 const endOf = (d) => { const x = new Date(d); x.setHours(23,59,59,999); return x; };
 // p1_78 fix #3: locale-aware range labels via window.t() (fallback to EN if i18n not ready)
 const T = (key, fallback) => (typeof window.t === 'function') ? (window.t(key) || fallback) : fallback;
 if (r === 'today') return { start: startOf(now), end: endOf(now), label: T('hs_range_today', 'Today') };
 if (r === 'yesterday') { const y = new Date(now); y.setDate(y.getDate()-1); return { start: startOf(y), end: endOf(y), label: T('hs_range_yesterday', 'Yesterday') }; }
 if (r === '7d') { const s = new Date(now); s.setDate(s.getDate()-6); return { start: startOf(s), end: endOf(now), label: T('hs_range_7d', '7 days') }; }
 if (r === '30d') { const s = new Date(now); s.setDate(s.getDate()-29); return { start: startOf(s), end: endOf(now), label: T('hs_range_30d', '30 days') }; }
 if (r === 'mtd') { const s = new Date(now.getFullYear(), now.getMonth(), 1); return { start: startOf(s), end: endOf(now), label: T('hs_range_mtd', 'MTD') }; }
 if (r === 'all') return { start: null, end: null, label: T('hs_range_all', 'All time') };
 if (r === 'custom') {
 const ss = document.getElementById('dashStartDate')?.value;
 const ee = document.getElementById('dashEndDate')?.value;
 return { start: ss ? startOf(new Date(ss)) : null, end: ee ? endOf(new Date(ee)) : null, label: (ss||'?')+' → '+(ee||'?') };
 }
 return { start: null, end: null, label: '—' };
}

window.renderDashboard = function() {
 const range = __getDashDateRange();
 let filteredSales = salesHistory;
 if (range.start && range.end) {
 filteredSales = salesHistory.filter(s => {
 const sd = new Date(s.created_at);
 return sd>= range.start && sd <= range.end;
 });
 }
 const rangeLabelEl = document.getElementById('dashRangeLabel');
 if (rangeLabelEl) rangeLabelEl.textContent = '— ' + range.label;

 // 2. Compute Core Metrics
 let totalSales = 0;
 let channelFreq = {};
 let itemCounts = {};

 let statusToFulfil = 0; let statusUnpaid = 0; let statusProcessing = 0; let statusReturn = 0;

 filteredSales.forEach(sale => {
 let rev = Number(sale.total || sale.total_amount || 0);
 totalSales = round2(totalSales + rev);
 
 // Channels
 let ch = sale.channel || 'POS Cashier';
 channelFreq[ch] = (channelFreq[ch] || 0) + rev;

 // Status
 let st = sale.status || 'Completed';
 if(st === 'To Fulfil') statusToFulfil++;
 if(st === 'Unpaid') statusUnpaid++;
 if(st === 'Processing') statusProcessing++;
 if(st === 'Return Request') statusReturn++;

 // Best Sellers parsing
 const itemsList = typeof sale.items === 'string' ? JSON.parse(sale.items) : sale.items;
 if(Array.isArray(itemsList)) {
 itemsList.forEach(item => {
 let sKey = item.sku;
 if(!itemCounts[sKey]) itemCounts[sKey] = { name: item.name, qty: 0, revenue: 0 };
 itemCounts[sKey].qty += Number(item.quantity);
 itemCounts[sKey].revenue = round2(itemCounts[sKey].revenue + Number(item.price) * Number(item.quantity));
 });
 }
 });

 const fmtMoney = (n) => Number(n).toLocaleString('en-MY', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
 document.getElementById("dashTotalSales").textContent = fmtMoney(totalSales);
 document.getElementById("dashTotalOrders").textContent = filteredSales.length;

 // Average Order Value
 const aov = filteredSales.length ? round2(totalSales / filteredSales.length) : 0;
 const aovEl = document.getElementById("dashAOV");
 if (aovEl) aovEl.textContent = 'RM ' + fmtMoney(aov);

 // Top Channel + share %
 let tChannel = "—"; let tVal = -1; let totalChVal = 0;
 for (let k in channelFreq) { totalChVal += channelFreq[k]; if(channelFreq[k]> tVal) { tChannel = k; tVal = channelFreq[k]; } }
 document.getElementById("dashTopChannel").textContent = tChannel;
 const shareEl = document.getElementById("dashTopChannelShare");
 if (shareEl) {
 if (totalChVal> 0 && tVal> 0) {
 const pct = Math.round((tVal / totalChVal) * 100);
 shareEl.textContent = pct + '% of revenue · RM ' + fmtMoney(tVal);
 } else { shareEl.textContent = 'No sales in range'; }
 }

 // p1_78 fix #8: helper — set badge value + hide parent .dash-alert when 0
 // (alerts with 0 count are noise; collapse them so Bos focuses on actionable items)
 const __setAlert = (id, val) => {
 const el = document.getElementById(id);
 if(!el) return;
 el.textContent = val;
 const card = el.closest('.dash-alert');
 if(card) card.style.display = (parseInt(val) > 0) ? '' : 'none';
 };

 // Status Board Update
 __setAlert('badgeToFulfil', statusToFulfil);
 __setAlert('badgeUnpaid', statusUnpaid);
 __setAlert('badgeProcessing', statusProcessing);
 __setAlert('badgeReturn', statusReturn);

 // 3. Inventory Stock Health
 let activeP=0; let draftP=0; let oosP=0; let lowP=0;
 masterProducts.forEach(p => {
 if(!isPublished(p)) { draftP++; return; }
 activeP++;

 let qty = inventoryBatches.filter(b=>b.sku===p.sku).reduce((sum, b)=>sum+b.qty_remaining,0);
 if(qty === 0) oosP++;
 else if(qty < 5) lowP++;
 });

 // Active Products is in Snapshot card (mini-row, not alert) — keep as-is
 document.getElementById("badgeActive").textContent = activeP;
 __setAlert('badgeDraft', draftP);
 __setAlert('badgeOos', oosP);
 __setAlert('badgeLow', lowP);

 // 4. CRM Customer Metrics
 // Calculate new buyers based on how many unique names are in filteredSales vs customersData. 
 // Simplified for MVP:
 let repeatC = customersData.filter(c => c.points> 0).length; // Assumption: points means repeated
 let membersC = customersData.filter(c => c.is_member === true).length;
 document.getElementById("dashNewBuyers").textContent = customersData.length; // Total saved unique customers
 document.getElementById("badgeRepeat").textContent = repeatC;
 document.getElementById("badgeMembers").textContent = membersC;

 // 5. Draw Top 10 List
 const topArr = Object.values(itemCounts).sort((a,b) => b.qty - a.qty).slice(0, 10);
 const tbodyLines = document.getElementById("topSellingList");
 tbodyLines.innerHTML = "";
 if(topArr.length === 0) tbodyLines.innerHTML = "<tr><td>No sales data</td></tr>";
 
 if (topArr.length === 0) {
 tbodyLines.innerHTML = '<tr><td colspan="4" style="padding:18px; text-align:center; color:var(--text-muted); font-size:12.5px;">Belum ada sales dalam range ni. Pilih range lebih luas atau buat sale pertama.</td></tr>';
 } else {
 // p1_158 — was innerHTML += in loop (O(n²) DOM reflow per push, crashed Safari).
 tbodyLines.innerHTML = topArr.map((o, i) => `<tr style="cursor:pointer;" onclick="window.__dashGoto('inv_database')">
 <td style="width:24px; font-weight:bold; color:#888;">#${i+1}</td>
 <td><strong>${o.name}</strong></td>
 <td style="color:#10b981; font-weight:700;">${o.qty} sold</td>
 <td style="text-align:right; font-weight:600;">RM ${fmtMoney(o.revenue)}</td>
 </tr>`).join('');
 }

 // 6. Draw Chart.js (Daily Sales)
 let dailyMap = {};
 filteredSales.forEach(s => {
 let dStr = new Date(s.created_at).toLocaleDateString('en-GB'); 
 dailyMap[dStr] = round2((dailyMap[dStr] || 0) + Number(s.total || s.total_amount || 0));
 });
 // Sort chronological
 let sortedDates = Object.keys(dailyMap).sort((a,b)=> new Date(a.split('/').reverse().join('-')) - new Date(b.split('/').reverse().join('-')));
 let gLabels = sortedDates;
 let gData = sortedDates.map(d => dailyMap[d]);

 const ctx = document.getElementById('salesChart');
 if(!ctx) return;
 
 if(salesChartInst) salesChartInst.destroy();
 salesChartInst = new Chart(ctx.getContext('2d'), {
 type: 'line',
 data: {
 labels: gLabels,
 datasets: [{
 label: 'RM',
 data: gData,
 backgroundColor: 'rgba(205, 124, 50, 0.12)',
 borderColor: '#CD7C32',
 borderWidth: 2,
 fill: true,
 tension: 0.35,
 pointRadius: gData.length> 14 ? 0 : 2,
 pointHoverRadius: 4
 }]
 },
 options: {
 responsive: true,
 maintainAspectRatio: false,
 plugins: { legend: { display: false }, tooltip: { callbacks: { label: (c) => 'RM ' + Number(c.parsed.y).toLocaleString('en-MY', {minimumFractionDigits:2, maximumFractionDigits:2}) } } },
 scales: { x: { display: false }, y: { display: false, beginAtZero: true } }
 }
 });

 // Freshness timestamp
 const stamp = document.getElementById('dashFreshStamp');
 if (stamp) stamp.textContent = new Date().toLocaleTimeString('en-MY', { hour:'2-digit', minute:'2-digit' });
}

// p1_159 — Test/Real management state
window.__ordHideTest = (function(){
 try { const s = localStorage.getItem('ordHideTest_v1'); return s === null ? true : s === '1'; }
 catch(e) { return true; }
})();
window.__ordSelected = window.__ordSelected || new Set();

function renderHistory() {
 const el = document.getElementById("salesHistory");
 if(!el) return;
 // p1_158 — was innerHTML += in 4957-row salesHistory loop → instant crash.
 // p1_159 — filter test orders by default + add per-card Mark Test/Real + checkbox bulk select.
 const hideTest = !!window.__ordHideTest;
 const testTotal = salesHistory.filter(s => s.is_test).length;
 // Update test count pill
 const cntEl = document.getElementById('ordersTestCount');
 if(cntEl) cntEl.textContent = testTotal + ' test orders' + (hideTest && testTotal > 0 ? ' (hidden)' : '');
 // Sync checkbox state
 const cb = document.getElementById('ordersHideTest');
 if(cb && cb.checked !== hideTest) cb.checked = hideTest;

 // Sort + filter test + cap 200
 const filteredList = hideTest ? salesHistory.filter(s => !s.is_test) : salesHistory;
 const sorted = filteredList.slice().sort((a, b) => new Date(b.created_at||0) - new Date(a.created_at||0)).slice(0, 200);
 el.innerHTML = sorted.map(sale => {
 const sc = sale.channel || 'POS Cashier';
 const st = sale.status || 'Completed';
 const stColor = st==='Completed'?'#000000': (st==='Unpaid'?'#6F6F6F': (st==='To Fulfil'?'#F37021':'#D80000'));
 const d = new Date(sale.created_at);
 const isTest = !!sale.is_test;
 const selected = window.__ordSelected.has(String(sale.id));
 const testBadge = isTest ? '<span style="background:#F59E0B; color:#FFF; padding:2px 8px; border-radius:50px; font-size:10px; font-weight:800; letter-spacing:0.4px; margin-left:6px;"><i data-lucide="flask-conical" style="width:10px; height:10px; vertical-align:-1px;"></i> TEST</span>' : '';
 return `
 <div class="history-card" style="${isTest ? 'border-left:4px solid #F59E0B; background:rgba(254,243,199,.15);' : ''}">
 <div style="display:flex; justify-content:space-between; margin-bottom:5px; align-items:center;">
 <div style="display:flex; align-items:center; gap:8px; flex:1;">
 <input type="checkbox" ${selected ? 'checked' : ''} onchange="window.__ordToggleSelect('${sale.id}', this.checked)" style="cursor:pointer;" title="Pilih untuk bulk action">
 <strong>[#${sale.id}] RM ${parseFloat(sale.total || sale.total_amount || 0).toFixed(2)}</strong>${testBadge}
 </div>
 <div style="display:flex; align-items:center; gap:6px;">
 <span class="badge-status" style="background:${stColor};">${st}</span>
 <button onclick="window.__ordMarkTest('${sale.id}', ${!isTest})" class="sy-btn secondary" style="font-size:10px; padding:4px 8px;" title="${isTest ? 'Mark as Real Order' : 'Mark as Test Order'}">
 <i data-lucide="${isTest ? 'check-circle' : 'flask-conical'}" style="width:10px; height:10px;"></i> ${isTest ? 'Mark Real' : 'Mark Test'}
 </button>
 </div>
 </div>
 <div style="font-size:13px; color:#666; margin-bottom:5px;">Buyer: ${sale.customer_name||'Walk-in'} • Channel: <strong>${sc}</strong> • ${sale.payment_method}</div>
 <div style="font-size:12px; color:#aaa;">${d.toLocaleDateString() + ' ' + d.toLocaleTimeString()}</div>
 </div>
 `;
 }).join('');
 if(filteredList.length > 200) {
 el.insertAdjacentHTML('beforeend', '<p style="text-align:center; padding:14px; color:#9CA3AF; font-size:11px;">Papar 200 transaksi terkini · total ' + filteredList.length + (hideTest && testTotal > 0 ? ' (+' + testTotal + ' test hidden)' : '') + ' rows</p>');
 }
 // Update bulk action buttons visibility
 window.__ordUpdateBulkBar();
 if(window.lucide && lucide.createIcons) lucide.createIcons();
}

// p1_159 — Mark single sale as test/real
window.__ordMarkTest = async function(saleId, isTest) {
 try {
 const u = window.currentUser || {};
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 const payload = {
 is_test: !!isTest,
 test_marked_by: isTest ? (u.name || 'Unknown') + ' (' + (u.staff_id || '?') + ')' : null,
 test_marked_at: isTest ? new Date().toISOString() : null
 };
 const { error } = await db.from('sales_history').update(payload).eq('id', saleId);
 if(error) throw error;
 // Update in-memory array
 const sale = salesHistory.find(s => String(s.id) === String(saleId));
 if(sale) Object.assign(sale, payload);
 if(typeof showToast === 'function') showToast('Sale #' + saleId + ' marked as ' + (isTest ? 'TEST' : 'REAL'), 'success');
 renderHistory();
 } catch(e) {
 if(typeof showToast === 'function') showToast('Mark gagal: ' + e.message, 'error');
 }
};

// p1_159 — Toggle filter
window.__ordToggleHideTest = function(checked) {
 window.__ordHideTest = !!checked;
 try { localStorage.setItem('ordHideTest_v1', checked ? '1' : '0'); } catch(e){}
 renderHistory();
};

// p1_159 — Bulk select handlers
window.__ordToggleSelect = function(id, checked) {
 if(checked) window.__ordSelected.add(String(id));
 else window.__ordSelected.delete(String(id));
 window.__ordUpdateBulkBar();
};
window.__ordSelectAll = function() {
 // select all currently rendered
 document.querySelectorAll('#salesHistory input[type="checkbox"]').forEach(cb => {
 const onchange = cb.getAttribute('onchange') || '';
 const m = onchange.match(/__ordToggleSelect\('([^']+)'/);
 if(m) { cb.checked = true; window.__ordSelected.add(m[1]); }
 });
 window.__ordUpdateBulkBar();
};
window.__ordClearSelection = function() {
 window.__ordSelected.clear();
 document.querySelectorAll('#salesHistory input[type="checkbox"]').forEach(cb => cb.checked = false);
 window.__ordUpdateBulkBar();
};
window.__ordUpdateBulkBar = function() {
 const n = window.__ordSelected.size;
 const t = document.getElementById('ordersBulkMarkTest');
 const r = document.getElementById('ordersBulkMarkReal');
 if(t) t.style.display = n > 0 ? '' : 'none';
 if(r) r.style.display = n > 0 ? '' : 'none';
 if(t && n > 0) t.innerHTML = '<i data-lucide="flask-conical" style="width:11px; height:11px;"></i> Mark ' + n + ' as TEST';
 if(r && n > 0) r.innerHTML = '<i data-lucide="check-circle" style="width:11px; height:11px;"></i> Mark ' + n + ' as REAL';
 if(window.lucide && lucide.createIcons) lucide.createIcons();
};
window.__ordBulkMark = async function(isTest) {
 const ids = Array.from(window.__ordSelected);
 if(!ids.length) return;
 if(!confirm('Mark ' + ids.length + ' sale(s) as ' + (isTest ? 'TEST' : 'REAL') + '?')) return;
 try {
 const u = window.currentUser || {};
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 const payload = {
 is_test: !!isTest,
 test_marked_by: isTest ? (u.name || 'Unknown') + ' (' + (u.staff_id || '?') + ')' : null,
 test_marked_at: isTest ? new Date().toISOString() : null
 };
 const { error } = await db.from('sales_history').update(payload).in('id', ids);
 if(error) throw error;
 // Update in-memory
 ids.forEach(id => {
 const sale = salesHistory.find(s => String(s.id) === String(id));
 if(sale) Object.assign(sale, payload);
 });
 window.__ordSelected.clear();
 if(typeof showToast === 'function') showToast(ids.length + ' sales marked as ' + (isTest ? 'TEST' : 'REAL'), 'success');
 renderHistory();
 } catch(e) {
 if(typeof showToast === 'function') showToast('Bulk mark gagal: ' + e.message, 'error');
 }
};

// ===================================
// INVENTORY WMS (BACKOFFICE)
// ===================================
// p1_49: Inventory Browse — KPIs + filter bar + card grid (default) / table (toggle)
window.invFilters = window.invFilters || { search: '', brand: '', cat: '', status: '' };
window.invView = window.invView || 'grid';

window.invHandleSearch = function(val) {
 window.invFilters.search = (val || '').toLowerCase().trim();
 renderWMS();
};
window.invSetFilter = function(key, val) {
 if(window.invFilters[key] === undefined) return;
 window.invFilters[key] = val || '';
 // sync the UI control if the call came from elsewhere (e.g. KPI tile click)
 const map = { brand: 'invBrandFilter', cat: 'invCatFilter', status: 'invStatusFilter' };
 const el = document.getElementById(map[key]);
 if(el && el.value !== window.invFilters[key]) el.value = window.invFilters[key];
 renderWMS();
};
window.invClearFilters = function() {
 window.invFilters = { search: '', brand: '', cat: '', status: '' };
 ['invSearchInput','invBrandFilter','invCatFilter','invStatusFilter'].forEach(id => {
 const el = document.getElementById(id); if(el) el.value = '';
 });
 renderWMS();
};
window.invSetView = function(view) {
 window.invView = view === 'table' ? 'table' : 'grid';
 document.querySelectorAll('.inv-view-btn').forEach(b => b.classList.toggle('is-active', b.dataset.view === window.invView));
 const grid = document.getElementById('invGridContainer');
 const tbl = document.getElementById('invTableContainer');
 if(grid) grid.style.display = window.invView === 'grid' ? '' : 'none';
 if(tbl) tbl.style.display = window.invView === 'table' ? '' : 'none';
 renderWMS();
};
window.invPopulateFilterOptions = function() {
 if(typeof masterProducts === 'undefined') return;
 const brands = new Set(), cats = new Set();
 masterProducts.forEach(p => { if(p.brand) brands.add(p.brand); if(p.category) cats.add(p.category); });
 const fillSel = (id, all, items) => {
 const sel = document.getElementById(id);
 if(!sel) return;
 const cur = sel.value;
 sel.innerHTML = '<option value="">' + all + '</option>' + Array.from(items).sort().map(v => `<option value="${String(v).replace(/"/g,'&quot;')}">${v}</option>`).join('');
 sel.value = cur;
 };
 fillSel('invBrandFilter', 'Semua Brand', brands);
 fillSel('invCatFilter', 'Semua Kategori', cats);
};

function renderWMS() {
 // 1) Inbound select stays (used elsewhere for batch inbound)
 const select = document.getElementById("inboundSkuSelect");
 if(select){
 // p1_158 — was innerHTML += in 963-product loop (Safari OOM trigger). Build string, assign once.
 select.innerHTML = '<option value="">-- Choose SKU --</option>' +
 masterProducts.map(p => `<option value="${p.sku}">[${p.sku}] ${p.name}</option>`).join('');
 }

 // 2) Bail if the new browse section isn't on the page (other callers expect renderWMS without the UI)
 const gridContainer = document.getElementById('invGridContainer');
 const tbody = document.getElementById('inventoryTableBody');
 if(!gridContainer && !tbody) return;

 // 3) Populate filter dropdowns (refresh in case product list grew)
 window.invPopulateFilterOptions();

 // 4) Compute KPIs over the FULL master list (not filtered)
 const totalProducts = masterProducts.length;
 const brands = new Set(masterProducts.map(p => p.brand).filter(Boolean));
 const cats = new Set(masterProducts.map(p => p.category).filter(Boolean));
 let lowCount = 0, oosCount = 0;
 masterProducts.forEach(p => {
 const stock = inventoryBatches.filter(b => b.sku === p.sku && b.qty_remaining > 0).reduce((s, b) => s + b.qty_remaining, 0);
 const reorderPt = parseFloat(p.reorder_point) || 5;
 if(stock <= 0) oosCount++;
 else if(stock <= reorderPt) lowCount++;
 });
 const setText = (id, txt) => { const el = document.getElementById(id); if(el) el.textContent = txt; };
 setText('invKpiTotal', totalProducts);
 setText('invKpiBrands', brands.size);
 setText('invKpiCats', cats.size);
 setText('invKpiLow', lowCount);
 setText('invKpiOOS', oosCount);

 // 5) Apply filters
 const f = window.invFilters;
 const filtered = masterProducts.filter(p => {
 if(f.search) {
 const q = f.search;
 if(!(p.name||'').toLowerCase().includes(q) && !(p.sku||'').toLowerCase().includes(q) && !(p.brand||'').toLowerCase().includes(q)) return false;
 }
 if(f.brand && p.brand !== f.brand) return false;
 if(f.cat && p.category !== f.cat) return false;
 if(f.status) {
 const stock = inventoryBatches.filter(b => b.sku === p.sku && b.qty_remaining > 0).reduce((s, b) => s + b.qty_remaining, 0);
 const reorderPt = parseFloat(p.reorder_point) || 5;
 if(f.status === 'active' && !isPublished(p)) return false;
 if(f.status === 'draft' && isPublished(p)) return false;
 if(f.status === 'oos' && stock > 0) return false;
 if(f.status === 'low' && (stock <= 0 || stock > reorderPt)) return false;
 }
 return true;
 });

 // 6) Active filter chips
 const banner = document.getElementById('invActiveFilters');
 if(banner) {
 const chips = [];
 const esc = (s) => String(s).replace(/'/g, "\\'").replace(/"/g, '&quot;');
 if(f.search) chips.push(`<span class="inv-chip">Cari: "${f.search}" <button onclick="document.getElementById('invSearchInput').value=''; window.invHandleSearch('')">×</button></span>`);
 if(f.brand) chips.push(`<span class="inv-chip">Brand: ${esc(f.brand)} <button onclick="window.invSetFilter('brand','')">×</button></span>`);
 if(f.cat) chips.push(`<span class="inv-chip">Kategori: ${esc(f.cat)} <button onclick="window.invSetFilter('cat','')">×</button></span>`);
 if(f.status) {
 const labels = { active:'Active', draft:'Draft', low:'Low Stock', oos:'Sold Out' };
 chips.push(`<span class="inv-chip">Status: ${labels[f.status]||f.status} <button onclick="window.invSetFilter('status','')">×</button></span>`);
 }
 if(chips.length) {
 banner.innerHTML = `<span class="inv-active-filters__count">Showing <strong>${filtered.length}</strong> dari ${masterProducts.length} produk</span>` + chips.join('') + ` <button class="inv-clear-all" onclick="window.invClearFilters()">Clear all</button>`;
 banner.style.display = '';
 } else {
 banner.innerHTML = '';
 banner.style.display = 'none';
 }
 }

 // 7) Render grid or table based on view
 if(window.invView === 'table') {
 renderInventoryTable(filtered);
 } else {
 renderInventoryGrid(filtered);
 }
}

// ============= p3_10 ONLINE ORDER FULFILLMENT ("Pesanan Online") =============
window.ffActiveTab = 'to_fulfil';
const FF_ONLINE_CHANNELS = ['TikTok Shop', 'Shopee', 'Web EasyStore'];
const FF_WINDOW_DAYS = 14;

window.ffSetTab = function(tab) {
 window.ffActiveTab = tab;
 document.querySelectorAll('#ffTabs .ff-tab').forEach(b => {
 b.classList.toggle('is-active', b.dataset.ffTab === tab);
 });
 window.renderFulfillment();
};

// Fulfillment stage overlay — stored in sales_history.metadata.ff_stage
function ffStage(sale) {
 const m = sale.metadata || {};
 if (m.ff_stage === 'shipped') return 'shipped';
 if (m.ff_stage === 'packed') return 'packed';
 return 'to_fulfil';
}

function ffOnlineOrders() {
 if (typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return [];
 const cutoff = Date.now() - FF_WINDOW_DAYS * 24 * 60 * 60 * 1000;
 return salesHistory.filter(s => {
 if (!FF_ONLINE_CHANNELS.includes(s.channel)) return false;
 const t = new Date(s.created_at || s.timestamp || 0).getTime();
 if (isNaN(t) || t < cutoff) return false;
 const st = (s.status || '').toLowerCase();
 if (st === 'voided' || st === 'cancelled' || st === 'refund') return false;
 return true;
 });
}

function ffChanClass(ch) {
 if (ch === 'TikTok Shop') return 'ff-card__chan--tiktok';
 if (ch === 'Shopee') return 'ff-card__chan--shopee';
 return 'ff-card__chan--web';
}

function ffParseItems(raw) {
 let items = raw;
 if (typeof items === 'string') { try { items = JSON.parse(items); } catch(e){ items = []; } }
 return Array.isArray(items) ? items : [];
}

// p1_81: build marketplace deep link / fallback list link for a sale order.
// Returns { url, label } or null.
function ffMarketplaceLink(o) {
 const m = o.metadata || {};
 const ch = (o.channel || '').toLowerCase();
 if(m.tiktok_order_id) {
 return { url: 'https://seller-my.tiktok.com/order/detail?order_no=' + encodeURIComponent(m.tiktok_order_id), label: 'TikTok', color: '#000' };
 }
 if(ch.includes('tiktok')) {
 return { url: 'https://seller-my.tiktok.com/order', label: 'TikTok', color: '#000' };
 }
 if(m.shopee_order_id) {
 return { url: 'https://seller.shopee.com.my/portal/sale/order/' + encodeURIComponent(m.shopee_order_id), label: 'Shopee', color: '#ee4d2d' };
 }
 if(ch.includes('shopee')) {
 return { url: 'https://seller.shopee.com.my/portal/sale/order', label: 'Shopee', color: '#ee4d2d' };
 }
 return null;
}

function ffCardHtml(o) {
 const stage = ffStage(o);
 const m = o.metadata || {};
 const ref = m.tiktok_order_id || m.easystore_order_number || m.easystore_order_id
 || (o.id ? ('#' + String(o.id).slice(0, 8)) : '#-');
 const dt = new Date(o.created_at || 0).toLocaleDateString('en-MY', { day:'numeric', month:'short', year:'numeric' });
 // p1_81: marketplace quick link button — opens TikTok / Shopee Seller Centre in new tab
 const mp = ffMarketplaceLink(o);
 const mpLink = mp ? '<a href="' + mp.url + '" target="_blank" rel="noopener" title="Lihat di ' + mp.label + ' Seller Centre" style="margin-left:6px; padding:2px 8px; background:' + mp.color + '; color:#fff; border-radius:4px; font-size:10px; font-weight:700; text-decoration:none; display:inline-flex; align-items:center; gap:3px; vertical-align:middle;"><i data-lucide="external-link" style="width:10px; height:10px;"></i> ' + mp.label + '</a>' : '';
 const total = Number(o.total || o.total_amount || 0).toLocaleString('en-MY', { minimumFractionDigits:2, maximumFractionDigits:2 });
 const itemsHtml = ffParseItems(o.items).map(it =>
 `<li>${it.qty || it.quantity || 1} &times; ${(it.sku||'')} — ${(it.name||'item')}</li>`).join('');
 const stageLabels = { to_fulfil:'Perlu Pack', packed:'Dah Pack', shipped:'Dah Hantar' };

 let actions = `<button class="ff-btn" onclick="ffPrintSlip('${o.id}')"><i data-lucide="printer"></i>Packing Slip</button>`;
 if (stage === 'to_fulfil') {
 actions += `<button class="ff-btn ff-btn--primary" onclick="ffMarkPacked('${o.id}')"><i data-lucide="package"></i>Tandai Dah Pack</button>`;
 } else if (stage === 'packed') {
 actions += `<button class="ff-btn ff-btn--ship" onclick="ffOpenShipForm('${o.id}')"><i data-lucide="truck"></i>Tandai Dah Hantar</button>`;
 }

 const trackHtml = (stage === 'shipped' && m.ff_tracking)
 ? `<div class="ff-card__track">Dihantar via <strong>${m.ff_courier||'-'}</strong> · Tracking: <strong>${m.ff_tracking}</strong></div>`
 : (stage === 'shipped' ? `<div class="ff-card__track">Dihantar via <strong>${m.ff_courier||'-'}</strong></div>` : '');

 return `<div class="ff-card" id="ffCard_${o.id}" style="cursor:pointer;" onclick="if(event.target.closest('button, a')) return; window.openOrderDetail('${o.id}')">
 <div class="ff-card__top">
 <div>
 <span class="ff-card__chan ${ffChanClass(o.channel)}">${o.channel||'-'}</span>
 <span class="ff-card__ref"> ${ref}</span>${mpLink}
 <span class="ff-card__meta"> · ${dt}</span>
 </div>
 <div style="text-align:right;">
 <div class="ff-card__total">RM ${total}</div>
 <span class="ff-card__stage ff-stage--${stage}">${stageLabels[stage]}</span>
 </div>
 </div>
 <div class="ff-card__cust"><i data-lucide="user" style="width:13px;height:13px;vertical-align:-2px;"></i> ${o.customer_name||'-'} · ${o.customer_phone||'-'}</div>
 <ul class="ff-card__items">${itemsHtml || '<li>(tiada item)</li>'}</ul>
 ${trackHtml}
 <div class="ff-card__actions">${actions}</div>
 </div>`;
}

// p1_87: Order Detail modal — EasyStore-style 2-column view.
window.__orderDetailCurrentId = null;
window.__orderDetailCurrentList = [];

window.openOrderDetail = function(orderId) {
 const sale = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory))
 ? salesHistory.find(s => String(s.id) === String(orderId)) : null;
 if(!sale) { if(typeof showToast === 'function') showToast('Order tak dijumpai', 'warn'); return; }
 window.__orderDetailCurrentId = orderId;
 try {
 window.__orderDetailCurrentList = (typeof ffOnlineOrders === 'function')
 ? ffOnlineOrders().map(o => o.id) : salesHistory.map(s => s.id);
 } catch(e) { window.__orderDetailCurrentList = []; }
 window.__renderOrderDetail(sale);
 const overlay = document.getElementById('orderDetailOverlay');
 if(overlay) overlay.style.display = 'flex';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

window.closeOrderDetail = function() {
 const overlay = document.getElementById('orderDetailOverlay');
 if(overlay) overlay.style.display = 'none';
 window.__orderDetailCurrentId = null;
};

window.odNavOrder = function(dir) {
 const list = window.__orderDetailCurrentList || [];
 const idx = list.indexOf(window.__orderDetailCurrentId);
 if(idx < 0) return;
 const next = idx + dir;
 if(next < 0 || next >= list.length) return;
 window.openOrderDetail(list[next]);
};

window.odPrintSlip = function() {
 if(typeof ffPrintSlip === 'function' && window.__orderDetailCurrentId) ffPrintSlip(window.__orderDetailCurrentId);
};

window.odPrintInvoice = function() {
 if(typeof showToast === 'function') showToast('Untuk B2B invoice rasmi, pakai Admin > Invoice & Quotation', 'info');
};

window.__renderOrderDetail = function(sale) {
 const m = sale.metadata || {};
 const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
 const ref = m.tiktok_order_id || m.shopee_order_id || m.easystore_order_number || m.easystore_order_id || sale.order_id || ('#' + String(sale.id || '').slice(0,8));
 document.getElementById('odHeaderRef').textContent = ref;
 const dt = sale.created_at ? new Date(sale.created_at) : null;
 document.getElementById('odHeaderDate').textContent = dt ? dt.toLocaleString('en-MY', { dateStyle:'medium', timeStyle:'short' }) : '—';

 const total = parseFloat(sale.total || sale.total_amount || 0);
 const paidStatus = (sale.payment_method && total > 0) ? 'Paid' : (sale.status === 'voided' ? 'Voided' : 'Pending');
 const ffStageVal = m.ff_stage || 'to_fulfil';
 const ffLabel = ffStageVal === 'shipped' ? 'Fulfilled' : (ffStageVal === 'packed' ? 'Packed' : 'Pending Pack');
 document.getElementById('odHeaderPills').innerHTML =
 '<span style="background:#D1FAE5; color:#065F46; padding:2px 8px; border-radius:4px; font-size:11px; font-weight:700;">' + paidStatus + '</span> ' +
 '<span style="background:#E0E7FF; color:#3730A3; padding:2px 8px; border-radius:4px; font-size:11px; font-weight:700;">' + ffLabel + '</span>';

 document.getElementById('odKpiTotal').textContent = 'RM ' + total.toFixed(2);
 document.getElementById('odKpiPaid').textContent = total.toFixed(2) + ' paid';
 const items = (typeof ffParseItems === 'function') ? ffParseItems(sale.items) : (Array.isArray(sale.items) ? sale.items : []);
 const itemCount = items.reduce((s, it) => s + (parseInt(it.qty || it.quantity || 1)), 0);
 document.getElementById('odKpiItems').textContent = itemCount;
 document.getElementById('odKpiFulfilled').textContent = ffStageVal === 'shipped' ? itemCount + ' fulfilled' : '0 fulfilled';

 const itemsHtml = items.length ? items.map(it => {
 const qty = parseInt(it.qty || it.quantity || 1);
 const name = it.name || it.product_name || 'item';
 const sku = it.sku || '';
 const price = parseFloat(it.price || it.unit_price || 0);
 return '<div style="display:flex; justify-content:space-between; padding:8px 0; border-bottom:1px solid #F1F5F9; font-size:13px;">'
 + '<div style="flex:1;"><strong>' + esc(name) + '</strong>' + (sku ? ' <span style="color:#94A3B8; font-size:11px;">[' + esc(sku) + ']</span>' : '') + '<br><span style="color:#64748B; font-size:11px;">RM ' + price.toFixed(2) + ' × ' + qty + '</span></div>'
 + '<div style="font-weight:700;">RM ' + (price * qty).toFixed(2) + '</div></div>';
 }).join('') : '<div style="text-align:center; color:#94A3B8; padding:14px;">(no items)</div>';
 document.getElementById('odItemsList').innerHTML = itemsHtml;

 const subtotal = items.reduce((s, it) => s + (parseFloat(it.price || it.unit_price || 0) * parseInt(it.qty || it.quantity || 1)), 0);
 const discount = parseFloat(m.vip_discount_amount || m.discount_amount || 0);
 const shipping = parseFloat(m.shipping_fee || 0);
 const tax = parseFloat(m.tax_amount || m.sst_amount || 0);
 document.getElementById('odBreakdown').innerHTML =
 '<div style="display:flex; justify-content:space-between;"><span style="color:#64748B;">Subtotal</span><span>RM ' + subtotal.toFixed(2) + '</span></div>'
 + (discount > 0 ? '<div style="display:flex; justify-content:space-between; color:#10B981;"><span>Discount</span><span>−RM ' + discount.toFixed(2) + '</span></div>' : '')
 + (shipping > 0 ? '<div style="display:flex; justify-content:space-between;"><span style="color:#64748B;">Shipping</span><span>RM ' + shipping.toFixed(2) + '</span></div>' : '')
 + (tax > 0 ? '<div style="display:flex; justify-content:space-between;"><span style="color:#64748B;">SST</span><span>RM ' + tax.toFixed(2) + '</span></div>' : '')
 + '<div style="display:flex; justify-content:space-between; padding-top:8px; border-top:1px solid #E2E8F0; font-weight:800; font-size:15px;"><span>Total</span><span>RM ' + total.toFixed(2) + '</span></div>';

 const ch = sale.channel || 'POS Cashier';
 const chColor = ch === 'TikTok Shop' ? '#000' : (ch === 'Shopee' ? '#ee4d2d' : (String(ch).includes('EasyStore') ? '#10B981' : '#6366F1'));
 document.getElementById('odChannelIcon').textContent = ch === 'TikTok Shop' ? 'T' : (ch === 'Shopee' ? 'S' : (String(ch).includes('EasyStore') ? 'E' : 'W'));
 document.getElementById('odChannelName').textContent = ch;
 document.getElementById('odChannelCard').style.borderLeft = '3px solid ' + chColor;

 const custName = sale.customer_name || '—';
 const custPhone = sale.customer_phone || '';
 const custEmail = sale.customer_email || '';
 document.getElementById('odCustomerInfo').innerHTML =
 '<strong>' + esc(custName) + '</strong>'
 + (custPhone ? '<br><span style="color:#64748B; font-size:12px;">' + esc(custPhone) + '</span>' : '')
 + (custEmail ? '<br><span style="color:#64748B; font-size:12px;">' + esc(custEmail) + '</span>' : '');

 const addr = m.shipping_address || m.address || null;
 if(addr && typeof addr === 'object') {
 const lines = [addr.name, addr.line1, addr.line2, [addr.city, addr.postcode].filter(Boolean).join(' '), [addr.state, addr.country].filter(Boolean).join(', ')].filter(Boolean);
 document.getElementById('odShippingAddr').textContent = lines.join('\n');
 } else if(typeof addr === 'string') {
 document.getElementById('odShippingAddr').textContent = addr;
 } else {
 document.getElementById('odShippingAddr').textContent = custPhone || '—';
 }

 const trackingCard = document.getElementById('odTrackingCard');
 if(m.ff_tracking || m.ff_courier) {
 trackingCard.style.display = 'block';
 document.getElementById('odTrackingInfo').innerHTML =
 (m.ff_courier ? '<strong>' + esc(m.ff_courier) + '</strong>' : '')
 + (m.ff_tracking ? '<br>Tracking: <code>' + esc(m.ff_tracking) + '</code>' : '');
 } else { trackingCard.style.display = 'none'; }

 const tagsList = document.getElementById('odTagsList');
 const tags = [];
 if(sale.channel) tags.push(sale.channel);
 if(sale.payment_method) tags.push(sale.payment_method);
 if(m.vip_customer_id) tags.push('VIP');
 tagsList.innerHTML = tags.length ? tags.map(t => '<span style="background:#E0E7FF; color:#3730A3; padding:2px 8px; border-radius:4px;">' + esc(t) + '</span>').join('') : '<span style="color:#94A3B8;">—</span>';

 const mpLink = document.getElementById('odMarketplaceLink');
 const mpLabel = document.getElementById('odMarketplaceLabel');
 if(typeof ffMarketplaceLink === 'function') {
 const mp = ffMarketplaceLink(sale);
 if(mp) {
 mpLink.style.display = 'inline-flex';
 mpLink.href = mp.url;
 mpLink.style.background = mp.color;
 if(mpLabel) mpLabel.textContent = mp.label + ' Seller';
 } else { mpLink.style.display = 'none'; }
 }

 const history = [];
 if(sale.created_at) history.push({ time: sale.created_at, label: 'Order placed · RM ' + total.toFixed(2) });
 if(sale.payment_method) history.push({ time: sale.created_at, label: 'Paid via ' + sale.payment_method });
 if(m.ff_packed_at) history.push({ time: m.ff_packed_at, label: 'Packed' });
 if(m.ff_shipped_at) history.push({ time: m.ff_shipped_at, label: 'Shipped' + (m.ff_courier ? ' via ' + m.ff_courier : '') });
 document.getElementById('odHistoryList').innerHTML = history.length
 ? history.map(h => {
 const t = h.time ? new Date(h.time).toLocaleString('en-MY', { dateStyle:'short', timeStyle:'short' }) : '';
 return '<div style="display:flex; gap:10px; padding:8px 0; border-bottom:1px solid #F1F5F9;"><div style="flex:1;">' + esc(h.label) + '</div><div style="font-size:11px; color:#94A3B8;">' + t + '</div></div>';
 }).join('')
 : '<div style="color:#94A3B8;">No history yet.</div>';
};

window.renderFulfillment = function() {
 const orders = ffOnlineOrders();
 const counts = { to_fulfil:0, packed:0, shipped:0 };
 orders.forEach(o => counts[ffStage(o)]++);
 const set = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
 set('ffKpiToFulfil', counts.to_fulfil);
 set('ffKpiPacked', counts.packed);
 set('ffKpiShipped', counts.shipped);

 const badge = document.getElementById('ffSidebarBadge');
 if (badge) {
 if (counts.to_fulfil > 0) { badge.style.display = ''; badge.textContent = counts.to_fulfil; }
 else badge.style.display = 'none';
 }

 const container = document.getElementById('ffOrderList');
 if (!container) return;
 const tab = window.ffActiveTab || 'to_fulfil';
 let list = (tab === 'all') ? orders : orders.filter(o => ffStage(o) === tab);
 list = list.sort((a,b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));
 if (!list.length) {
 container.innerHTML = '<div class="ff-empty">Tiada pesanan dalam kategori ni.</div>';
 return;
 }
 container.innerHTML = list.map(ffCardHtml).join('');
 if (window.lucide && lucide.createIcons) lucide.createIcons();
};

function ffFindOrder(id) {
 return (typeof salesHistory !== 'undefined' ? salesHistory : []).find(s => String(s.id) === String(id));
}

window.ffMarkPacked = async function(id) {
 const o = ffFindOrder(id);
 if (!o) return;
 const meta = Object.assign({}, o.metadata || {}, { ff_stage:'packed', ff_packed_at:new Date().toISOString() });
 try {
 const { error } = await db.from('sales_history').update({ metadata: meta }).eq('id', id);
 if (error) throw error;
 o.metadata = meta;
 if (typeof showToast === 'function') showToast('Order ditandai Dah Pack', 'success');
 window.renderFulfillment();
 } catch(e) {
 if (typeof showToast === 'function') showToast('Gagal kemaskini: ' + (e.message||e), 'error');
 }
};

window.ffOpenShipForm = function(id) {
 const card = document.getElementById('ffCard_' + id);
 if (!card || card.querySelector('.ff-ship-form')) return;
 const form = document.createElement('div');
 form.className = 'ff-ship-form';
 form.innerHTML = `
 <div><label>Kurier</label><input id="ffCourier_${id}" list="ffCourierList" placeholder="cth: J&amp;T Express"></div>
 <div><label>Tracking Number</label><input id="ffTrack_${id}" placeholder="cth: MY123456789"></div>
 <button class="ff-btn ff-btn--ship" onclick="ffMarkShipped('${id}')">Sahkan Hantar</button>`;
 card.querySelector('.ff-card__actions').after(form);
 const ci = document.getElementById('ffCourier_' + id);
 if (ci) ci.focus();
};

window.ffMarkShipped = async function(id) {
 const o = ffFindOrder(id);
 if (!o) return;
 const courier = ((document.getElementById('ffCourier_'+id)||{}).value || '').trim();
 const tracking = ((document.getElementById('ffTrack_'+id)||{}).value || '').trim();
 if (!courier) { if (typeof showToast === 'function') showToast('Isi nama kurier dulu', 'warn'); return; }
 const meta = Object.assign({}, o.metadata || {}, {
 ff_stage:'shipped', ff_courier:courier, ff_tracking:tracking, ff_shipped_at:new Date().toISOString()
 });
 try {
 const { error } = await db.from('sales_history').update({ metadata: meta, status:'Shipped' }).eq('id', id);
 if (error) throw error;
 o.metadata = meta; o.status = 'Shipped';
 if (typeof showToast === 'function') showToast('Order ditandai Dah Hantar', 'success');
 window.renderFulfillment();
 } catch(e) {
 if (typeof showToast === 'function') showToast('Gagal kemaskini: ' + (e.message||e), 'error');
 }
};

window.ffPrintSlip = function(id) {
 const o = ffFindOrder(id);
 if (!o) return;
 const m = o.metadata || {};
 const ref = m.tiktok_order_id || m.easystore_order_number || m.easystore_order_id || o.id;
 const rows = ffParseItems(o.items).map(it =>
 `<tr><td>${it.sku||''}</td><td>${it.name||'item'}</td><td style="text-align:center;">${it.qty||it.quantity||1}</td></tr>`).join('');
 const w = window.open('', '_blank', 'width=420,height=620');
 if (!w) { if (typeof showToast === 'function') showToast('Popup blocked — benarkan popup', 'warn'); return; }
 w.document.write(`<html><head><title>Packing Slip ${ref}</title>
 <style>body{font-family:-apple-system,Arial,sans-serif;padding:20px;font-size:13px;}
 h2{margin:0 0 4px;} .meta{color:#666;font-size:12px;margin-bottom:14px;line-height:1.5;}
 table{width:100%;border-collapse:collapse;} th,td{border-bottom:1px solid #ddd;padding:6px;text-align:left;}
 th{font-size:11px;text-transform:uppercase;color:#888;}</style></head><body>
 <h2>10 CAMP — Packing Slip</h2>
 <div class="meta"><strong>${o.channel||''}</strong> · ${ref}<br>${o.customer_name||''} · ${o.customer_phone||''}<br>
 ${new Date(o.created_at||0).toLocaleString('en-MY')}</div>
 <table><thead><tr><th>SKU</th><th>Produk</th><th>Qty</th></tr></thead><tbody>${rows||'<tr><td colspan=3>(tiada item)</td></tr>'}</tbody></table>
 <p style="margin-top:20px;font-size:12px;color:#666;">Jumlah: RM ${Number(o.total||0).toFixed(2)}</p>
 <scr`+`ipt>window.print();</scr`+`ipt></body></html>`);
 w.document.close();
};

// p1_300 — group products by parent_sku so variants collapse into 1 entry.
function __invGroupByParent(products) {
 const groups = new Map();
 for(const p of products) {
 const key = (p.parent_sku && String(p.parent_sku).trim()) ? ('p:' + p.parent_sku) : ('s:' + p.sku);
 if(!groups.has(key)) groups.set(key, []);
 groups.get(key).push(p);
 }
 return Array.from(groups.values());
}
function __invCleanTitle(name) {
 // strip the "— Variant / size" suffix that variant rows carry
 return String(name || 'Untitled').split('—')[0].trim() || 'Untitled';
}
function __invStockMap() {
 const m = {};
 for(const b of (inventoryBatches || [])) if(b.qty_remaining > 0) m[b.sku] = (m[b.sku] || 0) + b.qty_remaining;
 return m;
}

function renderInventoryGrid(products) {
 const container = document.getElementById('invGridContainer');
 if(!container) return;
 if(!products.length) {
 container.innerHTML = '<div class="inv-empty"><p>Tiada produk padan tapisan.</p><button class="btn-primary" onclick="window.invClearFilters()">Clear filters</button></div>';
 return;
 }
 const fmt = (n) => 'RM ' + (Number.isInteger(n) ? n : n.toFixed(2));
 const stockBySku = __invStockMap();
 let html = '';
 __invGroupByParent(products).forEach(list => {
 const lead = list.find(x => x.sku === x.parent_sku) || list[0];
 const isGroup = list.length > 1;
 const p = lead;
 const totalStock = list.reduce((s, v) => s + (stockBySku[v.sku] || 0), 0);
 const reorderPt = parseFloat(p.reorder_point) || 5;
 const stockState = totalStock <= 0 ? 'oos' : (totalStock <= reorderPt ? 'low' : 'ok');
 const stockLabel = stockState === 'oos' ? 'Sold Out' : (stockState === 'low' ? `${totalStock} ${p.unit||'Pcs'} · Low` : `${totalStock} ${p.unit||'Pcs'}`);
 const thumb = (p.images && p.images[0]) ? p.images[0] : 'https://placehold.co/300x300?text=No+Img';
 const skuEsc = String(p.sku).replace(/'/g, "\\'");
 const draftBadge = !isPublished(p) ? '<span class="inv-card__badge inv-card__badge--draft">Draft</span>' : '';
 const cost = parseFloat(p.cost_price || 0);
 const price = parseFloat(p.price || 0);
 const title = isGroup ? __invCleanTitle(p.name) : (p.name || 'Untitled');
 const skuLine = isGroup ? (p.parent_sku || p.sku) : p.sku;
 const variantBadge = isGroup ? `<span class="inv-card__badge" style="left:8px; right:auto; background:#101010; color:#fff;">${list.length} variants</span>` : '';
 html += `
 <button type="button" class="inv-card" data-sku="${p.sku}" onclick="window.openPdpModal('${skuEsc}')">
 <div class="inv-card__media">
 <img src="${thumb}" alt="${(title||'').replace(/"/g,'&quot;')}" loading="lazy" onerror="this.src='https://placehold.co/300x300?text=No+Img'">
 ${draftBadge}${variantBadge}
 <span class="inv-card__stock inv-card__stock--${stockState}">${stockLabel}</span>
 </div>
 <div class="inv-card__body">
 <div class="inv-card__meta">
 ${p.brand ? `<span class="inv-card__brand">${hesc(p.brand)}</span>` : ''}
 ${p.category ? `<span class="inv-card__cat">${hesc(p.category)}</span>` : ''}
 </div>
 <div class="inv-card__sku">${hesc(skuLine)}</div>
 <h3 class="inv-card__name">${hesc(title)}</h3>
 <div class="inv-card__footer">
 <div class="inv-card__price-wrap">
 <small>Cost ${fmt(cost)}</small>
 <strong>${fmt(price)}</strong>
 </div>
 <div class="inv-card__loc" title="Lokasi gudang">
 <i data-lucide="map-pin"></i>
 <span>${p.location_bin || '—'}</span>
 </div>
 </div>
 </div>
 </button>
 `;
 });
 container.innerHTML = html;
 if(window.lucide && lucide.createIcons) lucide.createIcons();
}

function renderInventoryTable(products) {
 const tbody = document.getElementById("inventoryTableBody");
 if(!tbody) return;
 let htmlBuf3 = "";
 const stockBySku = __invStockMap();
 __invGroupByParent(products).forEach(list => {
 const lead = list.find(x => x.sku === x.parent_sku) || list[0];
 const isGroup = list.length > 1;
 const p = lead;
 const totalStock = list.reduce((s, v) => s + (stockBySku[v.sku] || 0), 0);
 let thumb = "https://placehold.co/100x100?text=Img";
 let imgs = p.images || []; if(imgs.length> 0) thumb = imgs[0];
 let sBadge = isPublished(p) ? `<span style="color:green;font-size:10px;">Active</span>` : `<span style="color:red;font-size:10px;">Draft</span>`;
 const title = isGroup ? __invCleanTitle(p.name) : p.name;
 const skuLine = isGroup ? (p.parent_sku || p.sku) : p.sku;
 // variant summary: distinct colours + sizes across the group
 const colors = [...new Set(list.map(v => v.variant_color).filter(Boolean))];
 const sizes = [...new Set(list.map(v => v.variant_size).filter(Boolean))];
 const variantCell = isGroup
 ? `<span style="background:#101010; color:#fff; padding:2px 7px; border-radius:4px; font-size:10px; font-weight:700;">${list.length} variants</span><br><small style="color:#555;">${colors.map(hesc).join(' / ') || '-'}${sizes.length ? '<br>Saiz: ' + sizes.map(hesc).join(', ') : ''}</small>`
 : `Model: ${hesc(p.model_no) || '-'}<br>Variant: ${hesc(p.variant_size) || '-'} / ${hesc(p.variant_color) || '-'}<br>Dimensi: ${hesc(p.dimensions) || '-'} (${p.weight_kg ? hesc(p.weight_kg)+'Kg' : '-'})`;
 htmlBuf3 += `
 <tr onclick="window.openPdpModal('${String(p.sku).replace(/'/g, "\\'")}')" style="cursor:pointer;">
 <td>
 <img src="${thumb}" loading="lazy" decoding="async" style="width:45px; height:45px; object-fit:cover; border-radius:6px; background:#eee;"><br>
 ${sBadge}
 </td>
 <td>
 <span class="sku-badge">${hesc(skuLine)}</span> <span class="cat-badge">${hesc(p.category||'Uncategorized')}</span> ${(!isGroup && p.location_bin) ? `<span style="background:#fef08a; color:#854d0e; padding:3px 6px; border-radius:4px; font-size:10px;"> Loc: ${hesc(p.location_bin)}</span>` : ''}<br>
 <strong>${hesc(title)}</strong><br>
 <small style="color:#888;">Jenama: <strong>${hesc(p.brand || 'N/A')}</strong></small>
 </td>
 <td>
 <div style="font-size:12px; color:#555;">${variantCell}</div>
 </td>
 <td style="font-weight:bold; color:${totalStock <= 0 ? 'red' : 'green'};">
 ${totalStock} ${p.unit||'Pcs'}<br>
 <small style="font-weight:normal; color:#888;">${isGroup ? list.length + ' variant' : 'single'}</small>
 </td>
 <td>
 <div style="background:#F3F4F6; padding:5px; border-radius:4px; font-family:monospace; font-size:12px; border:1px solid #ddd; display:inline-block;">
 ${isGroup ? (colors.length ? list.length + ' variants' : (p.location_bin || '—')) : (p.location_bin || "Tiada Maklumat Rak")}
 </div>
 </td>
 <td>
 <small>Cost: RM${parseFloat(p.cost_price||0).toFixed(2)}</small><br>
 <strong>Sell: RM${parseFloat(p.price||0).toFixed(2)}</strong>
 </td>
 </tr>
 `;
 });
 tbody.innerHTML = htmlBuf3;
}

window.renderAuditCards = function() {
 renderStockTake();
}

// Global variable to keep track of audit timestamps per SKU
let auditTimestamps = {};

// p1_155 — Boot hydrate auditTimestamps from products_master.last_audited_at (was in-memory only,
// lost on every refresh). Now cross-device + historical (jan 2026 import via Sheet seeded 607 SKUs).
window.__hydrateAuditTimestamps = async function() {
 try {
 if(typeof db === 'undefined' || !db) return;
 const { data, error } = await db.from('products_master').select('sku,last_audited_at').not('last_audited_at', 'is', null).limit(5000);
 if(error) throw error;
 (data || []).forEach(r => { if(r.sku && r.last_audited_at) auditTimestamps[r.sku] = r.last_audited_at; });
 if(typeof renderStockTake === 'function' && document.getElementById('stockTakeSection')?.style.display !== 'none') {
 renderStockTake();
 }
 } catch(e) { /* silent */ }
};
// p1_157 — staggered start prevents iPad Safari from queueing all hydrates at once on weak Wi-Fi
setTimeout(() => { if(typeof window.__hydrateAuditTimestamps === 'function') window.__hydrateAuditTimestamps(); }, 5000);

