 if (!badge) return;
 const u = window.currentUser || (typeof currentUser !== 'undefined' ? currentUser : null);
 // Badge visible only for Bos + Aliff (the approvers/editors)
 if (!window.__rosterIsAdmin(u)) { badge.style.display = 'none'; return; }
