// =============================================================
// p1_50 — ESYNC HEALTH BADGE (HQ → Sync section)
// =============================================================
// Reads sync_status table (written by GH Actions cron) + counts EasyStore
// orders in sales_history. Renders status pill + last-run timestamp + manual
// refresh button. Auto-refreshes every 60s while syncSection is visible.
window.__esSyncTimer = null;

window.esSyncFmtAge = function(ts) {
 if(!ts) return { text: 'Never', mins: Infinity, color: 'red' };
 const t = new Date(ts).getTime();
 if(isNaN(t)) return { text: 'Unknown', mins: Infinity, color: 'red' };
 const mins = Math.floor((Date.now() - t) / 60000);
 let text, color;
 if(mins < 1) text = 'Just now';
 else if(mins < 60) text = mins + ' min ago';
 else if(mins < 1440) text = Math.floor(mins/60) + ' jam ' + (mins%60) + ' min ago';
 else text = Math.floor(mins/1440) + ' hari ago';
 if(mins < 30) color = 'green';
 else if(mins < 60) color = 'amber';
 else color = 'red';
 return { text, mins, color };
};

window.esSyncRefresh = async function() {
 const badge = document.getElementById('esSyncBadge');
 const badgeTxt = document.getElementById('esSyncBadgeText');
 const lastRunEl = document.getElementById('esSyncLastRun');
 const webhookEl = document.getElementById('esSyncWebhookStatus');
 const orderCountEl = document.getElementById('esSyncOrderCount');
 const card = document.getElementById('esSyncHealthCard');
 if(!badge || !badgeTxt) return; // section not rendered

 if(!db) {
 badgeTxt.textContent = 'DB Offline';
 return;
 }

 // 1. Last cron run timestamp
 let lastRunTs = null;
 try {
 const { data } = await db.from('sync_status').select('last_run_at,note').eq('source', 'easystore_cron').maybeSingle();
 if(data && data.last_run_at) lastRunTs = data.last_run_at;
 } catch(e) { /* table may not exist yet — first cron tick creates it */ }

 // 2. EasyStore order count + latest order time
 let esOrderCount = 0, latestOrderTs = null;
 try {
 const { count } = await db.from('sales_history').select('id', { count: 'exact', head: true }).ilike('channel', 'EasyStore%');
 esOrderCount = count || 0;
 const { data: latest } = await db.from('sales_history').select('created_at').ilike('channel', 'EasyStore%').order('created_at', { ascending: false }).limit(1).maybeSingle();
 if(latest && latest.created_at) latestOrderTs = latest.created_at;
 } catch(e) {}

 // 3. Webhook health (HEAD/GET /api/easystore-webhook returns {ok:true,hmac_configured:true,...})
 let webhookOk = null;
 try {
 const r = await fetch('/api/easystore-webhook', { method: 'GET' });
 if(r.ok) {
 const j = await r.json();
 webhookOk = !!(j.ok && j.hmac_configured && j.supabase_configured);
 } else { webhookOk = false; }
 } catch(e) { webhookOk = false; }

 // Render. Status pill reflects WORST of (cron freshness, latest order freshness).
 // If cron has run within 30 min OR a real order arrived within 30 min, healthy.
 const cronAge = window.esSyncFmtAge(lastRunTs);
 const orderAge = window.esSyncFmtAge(latestOrderTs);
 const bestColor = (cronAge.color === 'green' || orderAge.color === 'green') ? 'green'
 : ((cronAge.color === 'amber' || orderAge.color === 'amber') ? 'amber' : 'red');

 if(lastRunEl) lastRunEl.textContent = cronAge.text + (lastRunTs ? '' : ' (cron not run yet — first tick within 15 min)');
 if(webhookEl) webhookEl.textContent = webhookOk === null ? 'Checking…' : (webhookOk ? 'Endpoint OK' : 'Endpoint DOWN');
 if(orderCountEl) orderCountEl.textContent = esOrderCount + ' orders · latest ' + orderAge.text;

 // Badge styling
 badge.classList.remove('armed', 'unarmed');
 if(card) card.style.borderLeftColor = '';
 if(bestColor === 'green') {
 badge.classList.add('armed');
 badgeTxt.textContent = 'Healthy';
 if(card) card.style.borderLeftColor = 'var(--success)';
 } else if(bestColor === 'amber') {
 badge.classList.add('unarmed');
 badgeTxt.textContent = 'Stale (' + Math.min(cronAge.mins, orderAge.mins) + ' min)';
 if(card) card.style.borderLeftColor = 'var(--warning)';
 } else {
 badge.classList.add('unarmed');
 badge.style.color = '#DC2626';
 badge.style.background = 'rgba(239,68,68,.12)';
 badgeTxt.textContent = 'STALE — check webhook';
 if(card) card.style.borderLeftColor = 'var(--danger)';
 }
};

// Wrap renderSyncSection so the badge auto-refreshes when section opens + every 60s.
document.addEventListener('DOMContentLoaded', () => {
 const installEsSyncHook = () => {
 const orig = window.renderSyncSection;
 if(typeof orig !== 'function' || orig.__esSyncWrapped) return;
 window.renderSyncSection = function() {
 const r = orig.apply(this, arguments);
 setTimeout(() => window.esSyncRefresh(), 50);
 // p1_98 Fasa 3B + p1_104 — auto-load Shopee + TikTok status
 setTimeout(() => {
 if(typeof window.shopeeRefreshCronStatus === 'function') window.shopeeRefreshCronStatus();
 if(typeof window.shopeeRefreshConnInfo === 'function') window.shopeeRefreshConnInfo();
 if(typeof window.__refreshTiktokConnStatus === 'function') window.__refreshTiktokConnStatus();
 }, 100);
 if(window.__esSyncTimer) clearInterval(window.__esSyncTimer);
 window.__esSyncTimer = setInterval(() => {
 const sec = document.getElementById('syncSection');
 if(sec && sec.style.display !== 'none') window.esSyncRefresh();
 else if(window.__esSyncTimer) { clearInterval(window.__esSyncTimer); window.__esSyncTimer = null; }
 }, 60000);
 return r;
 };
 window.renderSyncSection.__esSyncWrapped = true;
 };
 // renderSyncSection is defined inside an IIFE in index.html — install after DOM ready.
 setTimeout(installEsSyncHook, 1500);
 setTimeout(installEsSyncHook, 4000); // backstop
});

// p3_1 Shopee Fasa 1 — Connect button handler
window.connectShopee = async function() {
 const status = document.getElementById('shopeeConnStatus');
 const setStatus = (txt, color) => {
 if(!status) return;
 status.textContent = txt;
 status.style.background = color === 'ok' ? 'rgba(16,185,129,.12)' : (color === 'err' ? 'rgba(239,68,68,.12)' : 'rgba(0,0,0,.06)');
 status.style.color = color === 'ok' ? '#10B981' : (color === 'err' ? '#EF4444' : 'var(--text-muted)');
 };
 try {
 setStatus('Loading auth link…', '');
 const res = await fetch('/api/shopee-auth-link', { cache: 'no-store' });
 const json = await res.json();
 if(!json.ok || !json.url) {
 setStatus('Setup tak lengkap', 'err');
 if(typeof showToast === 'function') showToast('Shopee setup error: ' + (json.error || 'unknown'), 'error');
 return;
 }
 setStatus('Buka tab Shopee…', '');
 const w = window.open(json.url, '_blank', 'noopener');
 if(!w) {
 setStatus('Popup blocked', 'err');
 if(typeof showToast === 'function') showToast('Browser block popup. Allow popup untuk www.10camp.com lepas tu cuba lagi.', 'warn');
 return;
 }
 setStatus('Tunggu authorize…', '');
 if(typeof showToast === 'function') showToast('Tab Shopee terbuka. Login + klik Confirm Authorization.', 'info');
 } catch(e) {
 setStatus('Gagal connect', 'err');
 if(typeof showToast === 'function') showToast('Error: ' + e.message, 'error');
 }
};

// p1_104 — TikTok parity: status check + pull orders mirror Shopee pattern
window.__refreshTiktokConnStatus = async function() {
 const pill = document.getElementById('tiktokConnStatus');
 const info = document.getElementById('tiktokConnInfo');
 if(!pill) return;
 try {
 const res = await fetch('/api/tiktok-sync-status', { cache: 'no-store' });
 const json = await res.json();
 if(json.error) { pill.textContent = 'ERROR'; pill.style.color = '#EF4444'; return; }
 if(!json.connected) {
 pill.textContent = 'NOT CONNECTED';
 pill.style.background = 'rgba(0,0,0,.06)'; pill.style.color = 'var(--text-muted)';
 if(info) info.style.display = 'none';
 return;
 }
 const c = json.connected;
 const hasCutover = !!c.direct_sync_cutover;
 pill.textContent = hasCutover ? 'CONNECTED (direct)' : 'CONNECTED (dryrun)';
 pill.style.background = hasCutover ? 'rgba(16,185,129,.12)' : 'rgba(245,158,11,.12)';
 pill.style.color = hasCutover ? '#10B981' : '#D97706';
 const expIn = new Date(c.access_token_expire_at).getTime() - Date.now();
 const expHr = Math.max(0, Math.floor(expIn / 3600000));
 if(info) {
 info.style.display = '';
 const lr = json.last_run;
 const t = json.today || {};
 const lastStr = lr ? `Last sync: ${Math.floor((Date.now()-new Date(lr.ran_at).getTime())/60000)} min lepas (${lr.orders_inserted || 0} new)` : 'Belum ada sync log';
 info.textContent = `${c.seller_name || c.open_id} · Token ${expHr}h · ${lastStr} · Hari ni: ${t.runs || 0} runs, ${t.inserted || 0} inserted, ${t.errors || 0} errors`;
 }
 } catch(e) {
 pill.textContent = 'ERROR';
 pill.style.color = '#EF4444';
 }
};

window.tiktokSyncOrders = async function(mode) {
 const result = document.getElementById('tiktokSyncResult');
 const setMsg = (txt, color) => {
 if(!result) return;
 result.style.display = '';
 result.style.color = color || 'var(--text-muted)';
 result.textContent = txt;
 };
 setMsg(mode === 'import' ? 'Tarik orders…' : 'Preview orders…');
 try {
 const res = await fetch(`/api/tiktok-sync?mode=${encodeURIComponent(mode)}`, { cache: 'no-store' });
 const json = await res.json();
 if(json.error) { setMsg('Error: ' + json.error, '#EF4444'); return; }
 if(json.refused) {
 setMsg(json.note || 'Import refused (cutover not set)', '#D97706');
 return;
 }
 const lines = [`Mode: ${json.mode}`];
 if(typeof json.orders_found === 'number') lines.push(`Orders dijumpai: ${json.orders_found}`);
 if(typeof json.mapped === 'number') lines.push(`Mapped: ${json.mapped} · Baharu: ${json.new || 0}`);
 if(typeof json.inserted === 'number') {
 lines.push(`Inserted: ${json.inserted}`);
 setMsg(lines.join(' · '), '#10B981');
 if(typeof showToast === 'function') showToast(`TikTok: ${json.inserted} order baharu disimpan.`, 'success');
 } else {
 if(json.note) lines.push(json.note);
 setMsg(lines.join(' · '));
 }
 } catch(e) { setMsg('Network error: ' + e.message, '#EF4444'); }
};

// p1_98 Fasa 2 — Pull Shopee orders into sales_history
window.shopeeSyncOrders = async function(mode) {
 const result = document.getElementById('shopeeSyncResult');
 const setMsg = (txt, color) => {
 if(!result) return;
 result.style.display = '';
 result.style.color = color || 'var(--text-muted)';
 result.textContent = txt;
 };
 const verb = mode === 'import' ? 'Tarik orders…' : 'Preview orders…';
 setMsg(verb);
 try {
 const res = await fetch(`/api/shopee-sync?mode=${encodeURIComponent(mode)}`, { cache: 'no-store' });
 const json = await res.json();
 if(json.error) {
 setMsg('Error: ' + json.error, '#EF4444');
 return;
 }
 const lines = [
 `Mode: ${json.mode} · env: ${json.env}`,
 `Orders dijumpai: ${json.orders_found ?? 0}`,
 `Mapped: ${json.mapped ?? 0} · Dah ada: ${json.already_imported ?? 0} · Baharu: ${json.new ?? 0}`
 ];
 if(json.mode === 'import' && typeof json.inserted === 'number') {
 lines.push(`Inserted: ${json.inserted}`);
 setMsg(lines.join(' · '), '#10B981');
 if(typeof showToast === 'function') showToast(`Shopee: ${json.inserted} order baharu disimpan.`, 'success');
 } else {
 if(json.note) lines.push(json.note);
 setMsg(lines.join(' · '));
 }
 } catch(e) {
 setMsg('Network error: ' + e.message, '#EF4444');
 }
};

// p1_100 — Push Shopee stock from POS inventory_batches
window.shopeeStockSync = async function(mode) {
 const result = document.getElementById('shopeeStockResult');
 const setMsg = (txt, color) => {
 if(!result) return;
 result.style.display = '';
 result.style.color = color || 'var(--text-muted)';
 result.textContent = txt;
 };
 const verb = mode === 'push' ? 'Push stock ke Shopee…' : (mode === 'dryrun' ? 'Compare stock…' : 'Listing items…');
 setMsg(verb);
 try {
 const res = await fetch(`/api/shopee-stock-sync?mode=${encodeURIComponent(mode)}`, { cache: 'no-store' });
 const json = await res.json();
 if(json.error) {
 setMsg('Error: ' + json.error, '#EF4444');
 return;
 }
 const lines = [`Mode: ${json.mode} · env: ${json.env}`];
 if(typeof json.shopee_items_total === 'number') lines.push(`Shopee items: ${json.shopee_items_total}`);
 if(typeof json.pos_skus_total === 'number') lines.push(`POS SKUs: ${json.pos_skus_total}`);
 if(typeof json.matched === 'number') lines.push(`Diffs jumpa: ${json.matched}`);
 if(typeof json.pushed === 'number') {
 lines.push(`Pushed: ${json.pushed}`);
 if(json.errors && json.errors.length) lines.push(`Errors: ${json.errors.length}`);
 setMsg(lines.join(' · '), json.ok ? '#10B981' : '#D97706');
 if(typeof showToast === 'function') showToast(`Shopee stock pushed: ${json.pushed} models.`, json.ok ? 'success' : 'warn');
 } else {
 if(json.note) lines.push(json.note);
 setMsg(lines.join(' · '));
 }
 } catch(e) {
 setMsg('Network error: ' + e.message, '#EF4444');
 }
};

// p1_98 Fasa 2D — Refresh cron status panel
window.shopeeRefreshCronStatus = async function() {
 const el = document.getElementById('shopeeCronStatus');
 if(!el) return;
 el.textContent = 'checking…';
 try {
 const res = await fetch('/api/shopee-sync-status', { cache: 'no-store' });
 const json = await res.json();
 if(json.error) { el.textContent = 'Error: ' + json.error; el.style.color = '#EF4444'; return; }
 if(!json.last_run) {
 el.textContent = 'Belum pernah jalan (cron baru deploy, tunggu max 15 min).';
 el.style.color = 'var(--text-muted)';
 return;
 }
 const lr = json.last_run;
 const t = json.today || {};
 const ago = (() => {
 const ms = Date.now() - new Date(lr.ran_at).getTime();
 const min = Math.floor(ms / 60000);
 if(min < 1) return 'baru sekejap tadi';
 if(min < 60) return min + ' min lepas';
 const hr = Math.floor(min / 60);
 if(hr < 24) return hr + ' jam lepas';
 return Math.floor(hr / 24) + ' hari lepas';
 })();
 const errPart = lr.error_message ? ` · ERROR: ${lr.error_message.slice(0, 60)}` : '';
 el.textContent = `Last: ${ago} · ${lr.orders_inserted || 0} new · Hari ni: ${t.runs || 0} runs, ${t.inserted || 0} inserted, ${t.errors || 0} errors${errPart}`;
 el.style.color = lr.error_message ? '#D97706' : 'var(--success)';
 } catch(e) {
 el.textContent = 'Network error';
 el.style.color = '#EF4444';
 }
};

// p1_98 Fasa 3B — Refresh connection info (shop_id, token expiry, connect/disconnect status)
window.shopeeRefreshConnInfo = async function() {
 const el = document.getElementById('shopeeConnInfo');
 const status = document.getElementById('shopeeConnStatus');
 if(!el || !status) return;
 try {
 const res = await fetch('/api/shopee-disconnect', { cache: 'no-store' });
 const json = await res.json();
 if(json.count === 0) {
 status.textContent = 'NOT CONNECTED';
 status.style.background = 'rgba(0,0,0,.06)'; status.style.color = 'var(--text-muted)';
 el.style.display = 'none';
 return;
 }
 const c = json.connected[0];
 const expIn = new Date(c.access_token_expire_at).getTime() - Date.now();
 const expHr = Math.max(0, Math.floor(expIn / 3600000));
 status.textContent = `CONNECTED (${json.env})`;
 status.style.background = 'rgba(16,185,129,.12)'; status.style.color = '#10B981';
 el.style.display = '';
 el.textContent = `Shop ID: ${c.shop_id} · Token expire ${expHr}h · Connected: ${new Date(c.created_at).toLocaleDateString()}`;
 } catch(e) { /* silent */ }
};

// p1_98 Fasa 3B — Disconnect shop (delete token row)
window.shopeeDisconnect = async function() {
 if(!confirm('Disconnect Shopee shop? Token akan dipadam dari POS. Untuk revoke fully, kena disconnect juga dari Shopee Seller Centre.')) return;
 try {
 const res = await fetch('/api/shopee-disconnect', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({})
 });
 const json = await res.json();
 if(json.error) {
 if(typeof showToast === 'function') showToast('Disconnect failed: ' + json.error, 'error');
 return;
 }
 if(typeof showToast === 'function') showToast('Shopee shop disconnected. Token dipadam.', 'success');
 setTimeout(() => window.shopeeRefreshConnInfo(), 300);
 } catch(e) {
 if(typeof showToast === 'function') showToast('Network error: ' + e.message, 'error');
 }
};

